INSERT INTO `book` (`id`, `author`, `edition`, `isbn`, `price`, `quantity`, `year`, `description`, `book_title`, `url`, `cover_image`, `publisher`, `status`, `created_at`) VALUES
(5928, 'Jimmy JoseAnthony R. CoxVibhu Paudyal', '', '978-3-031-51089-2', 22730, 0, '2024', 'The science of drug safety and pharmacovigilance has rapidly evolved in the 21st century. The knowledge and principles it contains are of increasing importance in clinical and practice settings. The aim of this book is to deal with the gap in knowledge about pharmacovigilance and drug safety, including the application of pharmacovigilance knowledge to individual patient cases in clinical practice. \n\nThe book is suitable for undergraduate healthcare professions, postgraduate students, researchers, clinical practitioners – including those with prescribing responsibilities. It will also be useful for professionals moving from a clinical practice role to a specialist pharmacovigilance role. For those already in a pharmacovigilance role, the book offers insight into the theory and practice of drug safety and pharmacovigilance in clinical settings.', 'Principles and Practice of Pharmacovigilance and Drug Safety', 'http://link.springer.com/book/10.1007/978-3-031-51089-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-51089-2.jpg', NULL, 'in_shelf', NULL),
(5929, 'Peter KesslerNicolas HardtKensuke Yamauchi', '', '978-3-031-06978-9', 16280, 0, '2024', 'This first volume in a multi-volume series considers the gains in information and knowledge that have resulted from preoperative and postoperative 3D imaging using new radiologic protocols in maxillofacial surgery, with the corresponding consequences for the surgeon. It contrasts the established standard techniques of orthognathic oral and maxillofacial surgery with new considerations and insights based on years of experience and analysis of clinical activity in this subspecialty of oral and maxillofacial surgery.\n\nThe book is deliberately structured so that the clinical situation is juxtaposed with a graphic representation for better understanding, which is intended to point out special situations that can in turn positively influence the surgical planning and execution of the procedure in order to avoid undesirable results in individual cases. Graphic representations illustrate the three-dimensionality of the complex splitting technique of the mandible where text or radiographs are insufficient.\n\n\nA corresponding book that combines clinical anatomical situations with pre- and postoperative preparation and clear explanation does not yet exist. It is aimed at a wide readership of students and professionals in oral and maxillofacial surgery, orthodontics, plastic and craniofacial surgery, and otolaryngology.', 'Illustrated Manual of Orthognathic Surgery', 'http://link.springer.com/book/10.1007/978-3-031-06978-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-06978-9.jpg', NULL, 'ordered', NULL),
(5930, 'Mahmoud Sakr', '', '978-3-031-48565-7', 15190, 0, '2024', 'The book provides a comprehensive overview of the challenges and debates on the diagnosis and treatment of midline neck swellings to clarify some uncertainties, make suggestions for resolving others, and establish strategies for achieving therapeutic success.\nIn addition to information on the surgical anatomy of the neck with particular emphasis on midline cervical regions, and the classification and clinical approach for diagnosis and management of neck swellings, the chapters explore cervical lymphadenopathy, swellings of the submental region, swellings of the hyoid bone region, swellings of the laryngeal/pharyngeal region, swellings of the tracheal region, and swellings of the supra-space of Burns. The last chapter emphasizes the importance of scheduling regular follow-ups as well as patient counselling and education.\nThe volume, enriched with color images and flowcharts, will be a key resource for head and neck surgeons, maxillofacial surgeons, orthopedic surgeons,endocrinologists, oncologists, pediatricians, and clinicians of other specialties as they face the most challenging midline neck swellings and work towards providing each patient with the best possible outcome.', 'Midline Neck Swellings', 'http://link.springer.com/book/10.1007/978-3-031-48565-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-48565-7.jpg', 'springer', 'popular_request', NULL),
(5931, 'Peter KesslerNicolas HardtKensuke Yamauchi', '', '978-3-031-49869-5', 14110, 0, '2024', 'The second of a multi-volume set takes into account the deficit of experience and knowledge gained from 3D preoperative planning and postoperative control using new radiological protocols in surgical procedures, with corresponding consequences. It contrasts the established standard techniques of orthognathic oral and maxillofacial surgery with alternatives that are based on years of experience and knowledge gained from better radiological analysis. Orthopaedic oral and maxillofacial surgery has experienced a renaissance in recent years, primarily due to three-dimensional radiological imaging.', 'Illustrated Manual of Orthognathic Surgery', 'http://link.springer.com/book/10.1007/978-3-031-49869-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-49869-5.jpg', NULL, NULL, NULL),
(5932, 'Louis Mandel', '', '978-3-031-50012-1', 13020, 0, '2024', 'This book will serve as a complete reference guide for the totality of salivary gland (SG) disease. Focusing on the clues available to the practitioner during the patient examination, it will completely review and update the available data concerning all manner of SG conditions. Looking beyond the perspectives of surgery, imaging, pathology, or sialendoscopy in diagnosis and therapy, this book will provide all professionals interested in the head and neck extensive and detailed diagnostic information about each SG entity. Achieving an accurate diagnosis involves the use of multiple clinical tools (history, physical examination, imaging, serology, biopsy etc). The indication for and significance of each of these investigative procedures will be discussed, integrated and photographically illustrated in tandem with the diagnostic review of the relevant SG entity. Besides a diagnostic review of readily diagnosed SG entities (Sjogren’s, sialolithiasis, infection etc), the book willcover subjects whose diagnoses have been inadequately described (juvenile recurrent parotitis, sarcoid, radioactive iodine for thyroid cancer, pediatric Sjogren’s, etc) or never reviewed (middle ear surgery and saliva, Stensen’s duct dilatation, first bite syndrome, HIV paraparotid fat, etc) in other published texts. It will be organized by diagnosis.\nWritten by an expert in the field with over six decades of clinical experience, Clinical Management of Salivary Gland Disorders will call attention to the large number of presenting patients who can be categorized as \"false-positives.\" This includes a psychosomatic group with perceptual salivary complaints, patients with masseteric hypertrophy, paraglandular opacities misdiagnosed as sialoliths, dental caries thought to have a salivary origin and more. Finally, this book will offer thorough methodology for identifying and diagnosing these initially confusing problems. An exhaustive resource for the field of salivary gland complaints, this book wil', 'Clinical Management of Salivary Gland Disorders', 'http://link.springer.com/book/10.1007/978-3-031-50012-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-50012-1.jpg', NULL, NULL, NULL),
(5933, 'Michael H. Carstens', '', '978-3-031-15636-6', 23220, 0, '2023', 'Focusing on the anatomy of the head and neck, this book begins at the cellular level of development, detailing bone, muscle, blood supply, and innervation along the way. It illustrates the origin of each tissue structure to aid in making prognoses beyond the surface deformation, offering typical issues seen in the craniofacial region, for example. Written by a pediatric Craniofacial plastic surgeon and intended for clinicians and residents in the areas of plastic surgery, ENT, maxillofacial surgery, and orthodontistry, this book is the first of its kind to focus so intently on evolution of the craniofacial structure. It is neatly broken up into two distinct sections.\nThe first section is meant for readers to gain a fundamental understanding of the development of craniofacial structures, from embryo onward, relying on the concepts of the Neuromeric Theory. The chapters in the first section of the book trace the development of the typical patient. The second section offers clinical examples of how the Neuromeric Theory can be used to repair or reconstruct various regions of the head and neck. Craniofacial clefts, including cleft lip and palate, ocular hypotelorism, anencephaly, craniosynostosis and more are detailed. Understanding the formation of the tissue structures involved in any given genetic deformation or anomaly enables the clinician to provide a more satisfying outcome for the patient, both structurally and aesthetically. New and current therapeutic options are explored and supported through original illustrations and photographs to aid in determining the best treatment for each individual patient.\nEmbryological Principles of Craniofacial Structure bridges the gap between introductory books on the basic anatomy of the head and neck and the detailed understanding required for corrective surgery of craniofacial defects.', 'The Embryologic Basis of Craniofacial Structure', 'http://link.springer.com/book/10.1007/978-3-031-15636-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-15636-6.jpg', NULL, NULL, NULL),
(5934, 'Damian J. J. FarnellRenata Medeiros Mirra', '', '978-3-031-26010-0', 22730, 0, '2023', 'This book discusses the theory and practice of teaching biostatistics to students in the life sciences, in particular medical and dental trainees and researchers, as well as its crucial importance to biomedical research and evidence-based health care. Specific tools and resources to biostatistics teaching (e.g., “R shiny”) are described, and how they can be used effectively to increase interaction with students and improve engagement with the subject. The book is structured into three parts: teaching and learning of statistics in medicine and allied health sciences; the move to online learning and online learning methods, especially in light of the impact of COVID-19; and computer tools and resources. It provides a unique insight into teaching biostatistics to medical and dental students from some of the most prominent biostatisticians who also have a very strong interest in biostatistics pedagogy.\n \nBiostatistics teaching is important for maintainingthe quality of biomedical research and also in evidence-based medicine, both of which are key to the health and well-being of the world population. This book is particularly useful to readers who are new to the field of biostatistics teaching as well as to more experienced teachers as it presents the latest accounts of the teaching and learning of biostatistics, recent experiences of increased use of online teaching, and useful computer resources and tools for teaching biostatistics.', 'Teaching Biostatistics in Medicine and Allied Health Sciences', 'http://link.springer.com/book/10.1007/978-3-031-26010-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-26010-0.jpg', NULL, NULL, NULL),
(5935, 'Harald EufingerAlexander KÃ¼blerHenning Schliephake', '', '978-3-662-66844-3', 22680, 0, '2023', 'This book gives a detailed account of all procedures in oral and maxillofacial surgery, illustrated with over 1000 accurate surgical drawings and, new to the 5th edition, photographic illustrations. All surgical procedures are described in step-by-step illustrations in instructive texts. The detailed drawings explain the individual surgical steps. In addition, the reader receives tips and tricks from top experts in maxillofacial surgery for use in the operating room. In this new edition, \"Aesthetic Facial Surgery\" has been completely revised under new authorship. It covers dentoalveolar surgery with implantology, septic surgery and the entire traumatology of the maxillofacial region, the surgical treatment of cleft lip and palate, orthopedic surgery of the craniofacial region, the entire tumor surgery including plastic reconstructive surgery and the modern procedures of microvascular tissue transfer. This work is the ideal surgical textbook for the beginner and the expert. The 3rd and4th editions were published under the editors \"Hausamen et al.\" and are among the standard works in oral and maxillofacial surgery. For doctors in oral and maxillofacial surgery, plastic and reconstructive surgery, trauma surgery.', 'Oral and maxillofacial surgery', 'http://link.springer.com/book/10.1007/978-3-662-66844-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-66844-3.jpg', NULL, NULL, NULL),
(5936, 'Peter M. BaptistaRodolfo Lugo SaldaÃ±aSteve Amado', '', '978-3-031-35225-6', 21700, 0, '2023', 'The book provides a comprehensive overview of the medical implications, pathophysiology, and treatment of Obstructive Sleep Apnea (OSA), a disease that creates increased health risks, most notably those related to the cardiovascular and cerebrovascular systems.\nThe opening chapters are dedicated to the definition of OSA, its diagnosis, and the treatment options. The following chapters address primary forms of disease presentation in each medical field, with the latest evidence.Given its characteristics, the book will enable the reader to adopt a broad strategy for evaluating and managing OSA patients. In addition, it will be a valuable resource for all the clinicians who treat sleep-disordered breathing, including otolaryngologists, pulmonologists, cardiologists, neurologists, etc.', 'Obstructive Sleep Apnea', 'http://link.springer.com/book/10.1007/978-3-031-35225-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-35225-6.jpg', NULL, NULL, NULL),
(5937, 'Christine E. NiekrashElie M. FerneiniMichael T. Goupil', '', '978-3-031-38567-4', 21700, 0, '2023', 'This multi-authored, multi-institutional, and multi-specialty based book is designed as a guide for the medical practitioner on dentistry and dental emergencies. The book is divided into five sections for ease of use: The first section gives an overview of local head and neck anatomy; the second section provides a discussion of potential head and neck infections; the third section discusses important perioral pathology; the fourth section gives an overview on the management of soft and hard tissue trauma; the fifth section discusses some other topics which might be encountered by the medical professional like managing patient anxiety and pain. \n\n\nFeaturing dozens of pictures and diagrams to bring each scenario to life, the editors and contributors utilize their extensive academic experience and prior publication experience with multiple scientific articles and chapters to provide a resource for handling any dental emergency. \n\n\nDental Science for the Medical Professional is a must-have resource for multiple medical and surgical professionals including: Primary care physicians, Emergency room physicians, Family physicians, General surgeons, Medical and Dental Students, Urgent care providers, and Mid-level Providers.', 'Dental Science for the Medical Professional', 'http://link.springer.com/book/10.1007/978-3-031-38567-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-38567-4.jpg', NULL, NULL, NULL),
(5938, 'Ulrich Meyer', '', '978-3-031-28069-6', 16280, 0, '2023', 'This is the second volume in an interdisciplinary three-book series covering the full range of biological, clinical, and surgical aspects in the evaluation, diagnosis, and treatment of patients with craniofacial malformations. In this volume, readers will find detailed discussion of the treatment principles for craniosynostoses, orofacial clefts, branchio-oculo-facial syndromes, soft tissue malformations, dysgnathia and rare syndromes. In addition to description of important facets of treatment and the treatment planning process, guidance is offered on diagnosis and disease classification. Featuring numerous high-quality illustrations, the book will be of value for all clinicians and trainees who are involved in the management of patients with these malformations. The accompanying two volumes discuss the biological basis of disease, psychological aspects, and diagnostic issues and present surgical techniques with the aid of accompanying surgical videos.', 'Fundamentals of Craniofacial Malformations', 'http://link.springer.com/book/10.1007/978-3-031-28069-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-28069-6.jpg', NULL, NULL, NULL),
(5939, 'Marco KestingRainer LutzManuel Weber', '', '978-3-031-33521-1', 16280, 0, '2023', 'Books on cleft surgery are usually very specific and written for experts in the field. A basic surgical learning manual on the techniques of cleft surgery has been missing on the market so far. Surgical atlases do not contain all surgical steps and make it difficult for beginners in cleft surgery to understand the surgical concept in the operating room. The technique of cleft surgery is often passed on directly from teacher to student without using a didactically elaborated teaching concept.\nThis book closes precisely this gap. Thus, cleft surgery is presented systematically - with first steps on an innovative training model, didactically meaningful and with numerous detailed illustrations. Each chapter begins with information on the historical background. As a start, there is a brief description on how the established surgical techniques became standard and which considerations led to these concepts. Then anatomical basics, as well as preoperative considerations are presented. Elaborate schematic drawings and illustrations are used for this purpose. Each surgical technique is then explained and shown step by step with numerous pictures. A simple training model offers the opportunity to simulate and practice lip closure techniques step by step. Finally, there are expert tips and recommendations for further reading.\n\nThe book presents an international standard for all surgeons learning cleft surgery. However, it can also be helpful for experts in the field, e. g. for looking up concepts in rarer cleft types such as lateral facial clefts.', 'A Visual Guide for Cleft Surgeons', 'http://link.springer.com/book/10.1007/978-3-031-33521-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-33521-1.jpg', NULL, NULL, NULL),
(5940, 'Pat Ricalde', '', '978-3-031-24636-4', 15190, 0, '2023', 'This book aims to teach the reader about all aspects of maxillary cleft reconstruction, with emphasis on management of the patient born with a congenital anomaly, cleft lip and palate, which will usually have been managed by several different providers during earlier childhood. Clinical anatomy, clinical and imaging assessment (including the role of CBCT), orthodontic considerations, surgical repair techniques, the approach in special situations, and outcome evaluation are all thoroughly described. While the focus is especially on the patient with mixed dentition, due attention is paid to prior influences on that stage, as well as to the changes that will occur subsequently.\nMaxillary cleft reconstruction is a uniquely multidisciplinary component in reconstruction of cleft lip and palate. It is one of the most complex phases of rehabilitation, wherein orthodontics, dentistry, and surgery are immediately involved but presentation and eventual outcomes are heavily influenced byoperations during the first year of life and by growth that is unpredictable and iatrogenically altered. This book will be of high educational and practical value to all who have an interest in the management of patients with cleft lip and palate.', 'Cleft Maxillary Reconstruction', 'http://link.springer.com/book/10.1007/978-3-031-24636-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-24636-4.jpg', NULL, NULL, NULL),
(5941, 'Arash KhojastehAshraf F. AyoubNasser Nadjmi', '', '978-981-19-8602-4', 13020, 0, '2023', 'This book covers the application of emerging technologies, occurring after the 4th industrial revolution, in oral and maxillofacial surgery (OMFS) and introduces a new era of personalized medicine in this discipline. It describes the manufacturing and data acquisition methods, in detail, including the advantages and disadvantages of each process. The workflow of using the emerging technologies in reconstructive treatments, orthognathic surgery, implant dentistry, robotic surgery and bio‑fabrication have been covered in separate chapters.\nSeveral related cases in conjunction with the workflow are presented and discussed as clinical examples of each, for practical discussion of the workflow and process trajectory. Each chapters provides introduction, definition, application and plausible pitfalls of employing these technologies in specific areas. Given the multiple materials and techniques, the logic behind selection of each in different fields of practice and thorough explanation of process provides surgeons with a background on how and why a certain approach is employed, and if application of emerging technologies would outdo traditional treatment processes.\nThe importance of fabricating living tissues is discussed as one of the most recent progresses in the field. The bench-to-bedside transition, their clinical application, and their remarkable positive impact on oral and maxillofacial surgical procedures are covered. This book is arranged for oral and maxillofacial, and plastic surgeons and in-training-fellows in associated fields.', 'Emerging Technologies in Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-981-19-8602-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-981-19-8602-4.jpg', NULL, NULL, NULL),
(5942, 'Stefan Abela', '', '978-3-031-21025-9', 10850, 0, '2023', 'This book outlines strategies for dealing with the management problems that arise in the healthcare profession, and it prepares the reader for interviews, examinations and the supervision of a team.\nIt opens with an overview of the NHS, its evidence-based practice and healthcare regulations. Subsequent chapters discuss data protection, management of new business cases, formal complaints and inappropriate use of social media. Information is provided on the recruitment of new junior trainees, the management of underperforming allied health professionals, and the handling of injuries sustained at work. This book is ideal for final-year medical and dental undergraduate students, foundation year doctors, core trainees, junior and senior specialists and newly-appointed consultants.', 'Leadership and Management in Healthcare', 'http://link.springer.com/book/10.1007/978-3-031-21025-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-21025-9.jpg', NULL, NULL, NULL),
(5943, 'Ourania Varsou', '', '978-3-031-22452-2', 9770, 0, '2023', 'This volume is a unique compendium of professional and practical knowledge on new paradigms and approaches in Teaching, Research, Innovation and Public Engagement that is currently missing from the Higher Education market. The intended audience includes healthcare, biomedical and physical sciences discipline specialists active in teaching, along with their students, science communicators associated with the above subjects and academics involved in relevant research/innovation. Its contents will be organised under the following three themes: 1) Scholarship of Teaching and Learning discussing pertinent knowledge, in this area, and inspiring educators to pursue similar medical humanities endeavours. The focus is on pedagogy/teaching including professional knowledge/expertise, reflections, literature reviews and evidence on a wide range of medical, biomedical and physical sciences topics interweaved with humanities. 2) Research and Innovation discussing novel work and paradigms as examples for future use/implementation. The focus is firstly on original research utilising cutting-edge technology and secondly on innovation with discussions around poetry and building communities. 3) Public Engagement discussing relevant science communication paradigms transferable to other settings and applications. The focus is on practical knowledge and examples from a wide range of healthcare and biomedical sciences topics interweaved with humanities while also exploring the hidden curriculum of public engagement and heritage practices through the lens of equality, diversity and inclusion. All chapter authors are renowned experts in their respective fields, who bring together a wealth of professional and practical knowledge, enriching the narrative of this edited book volume.', 'Teaching, Research, Innovation and Public Engagement', 'http://link.springer.com/book/10.1007/978-3-031-22452-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-22452-2.jpg', NULL, NULL, NULL),
(5944, 'Vivien Schmeling Piccin', '', '978-3-031-50292-7', 9770, 0, '2023', 'Providing good quality sleep to people with sleep-related breathing disorders is a major challenge for respiratory physiotherapists and other professionals working in the field. These patients chronically suffer from the negative effects of interrupted sleep, a consequence of increased respiratory effort, disturbing arousals and constant hypoxias. Using positive pressure equipment every night goes far beyond simply programming a device and choosing a mask.\nThis book provides a deep analysis and interpretation of the respiratory flow curves during sleep in patients using pressure therapy. It also helps the reader to understand the influence of the physiological and pathophysiological processes on the respiratory pattern during sleep.\n\nConsisting of multiples figures, graphics and case examples, this practical work offers a comprehensive and didactic approach to using pressure therapy for sleep apnea treatment. The target audience is Sleep Medicine clinicians,as well as physicians from different specialties (Otolaryngologists, Pulmonologists, Neurologists), Physical Therapists, Dentists, Speech Pathologists, and all other professionals who work with sleep-disordered breathing field.', 'Monitoring Positive Pressure Therapy in Sleep-Related Breathing Disorders', 'http://link.springer.com/book/10.1007/978-3-031-50292-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-50292-7.jpg', NULL, 'popular_request', NULL),
(5945, 'Prof. Dr. Dr. Hans-Robert MetelmannProf. Dr. Thomas von WoedtkeProf. Dr. Klaus-Dieter WeltmannProf. Dr. med. Steffen Emmert', '', '978-3-030-87857-3', 22730, 0, '2022', 'This textbook addresses the growing international need for a practical manual that teaches physicians how to apply cold atmospheric pressure plasma (CAP) in the day‐to‐day provision of patient healthcare.\n\n\n\nThe book introduces readers to the concept of CAP, how it works, and how safe it is, before describing several diseases and other medical indications for its application. The book subsequently provides guidelines for daily clinical practice, e.g. for treating chronic wounds, decontaminating infected skin lesions, and rendering multi-resistant bacteria inert, as well as a detailed overview of plasma devices. In closing, it addresses organizational aspects, which are essential to cultivating and maintaining quality standards in the application of cold medical plasma.\n\n\nThis textbook offers a unique educational resource and provides relevant information on plasma medicine as an emerging multidisciplinary discipline. Practitioners will appreciate this integrated, comprehensive guide, which is also suitable for advanced students of medicine and dentistry, and for nurses serving on plasma-assisted medical teams.', 'Textbook of Good Clinical Practice in Cold Plasma Therapy', 'http://link.springer.com/book/10.1007/978-3-030-87857-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-87857-3.jpg', NULL, NULL, NULL),
(5946, 'Michael MiloroG. E. GhaliPeter E. LarsenPeter Waite', '', '978-3-030-91920-7', 22730, 0, '2022', 'The new edition of this outstanding reference textbook, in two volumes, offers comprehensive and authoritative coverage of the contemporary specialty of oral and maxillofacial surgery. The aim is to provide an all-encompassing, user-friendly source of information that will meet the needs of residents and experienced surgeons in clinical practice and will also serve as an ideal companion during preparation for board certification or recertification examinations. All of the authors, numbering some 100, are distinguished experts in the areas that they address. The new edition takes full account of the significant changes in clinical practice and guidelines that have occurred during recent years. Readers will find clear explanations of the practical application of surgical principles, with a wealth of supporting illustrative material, including atlas-type illustrations to complement the descriptions of specific procedures. The fourth edition of Peterson’s Principles of Oral and Maxillofacial Surgery is a truly exceptional resource for clinicians and students alike.', 'Petersonâ€™s Principles of Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-91920-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-91920-7.jpg', 'Springer Nature', NULL, NULL),
(5947, 'Percy Rossell-Perry', '', '978-3-030-98400-7', 16280, 0, '2022', 'This book encompasses diagnostic, treatment and prevention of bad results and complications associated with cleft lip and palate surgery. Illustrated by more than 200 images and based on a 25 years’ experience of the editor, the work includes the whole spectrum of complications based on case studies, as well as management and prevention protocols. Divided in nine didactic parts, the chapters present complications related to anesthesia, lip asymmetry, scar disorders, postoperative dehiscence, secondary nose deformities besides dentoeskeletal sequels.   \nAtlas of Non-Desirable Outcomes in Cleft Lip and Palate Surgery will benefit plastic surgeons, pediatric surgeons, otolaryngologists, maxillofacial surgeons, head and neck surgeons, dentists and anesthesiologists.', 'Atlas of Non-Desirable Outcomes in Cleft Lip and Palate Surgery', 'http://link.springer.com/book/10.1007/978-3-030-98400-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-98400-7.jpg', NULL, NULL, NULL),
(5948, 'MD Elie M. FerneiniMichael T. GoupilSteven Halepas', '', '978-3-030-89563-1', 11940, 0, '2022', 'The multi-authored, multi-institutional, and multi-specialty-based text is designed as a valuable resource for surgeons working on the maxillofacial region. Meant to be a clinically based history of the past, the present, and the future of the field, this is a one-of-a-kind text that will cater to a variety of professions: from oral & maxillofacial surgeons, plastic and reconstructive surgeons, otolaryngologists – head and neck surgeons, cosmetic surgeons and the general dental practitioner.', 'The History of Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-89563-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-89563-1.jpg', NULL, NULL, NULL),
(5949, 'Antigoni DelantoniKaan Orhan', '', '978-3-030-96840-3', 11940, 0, '2022', 'Enriched by radiographic images and illustrations, this book explores the anatomy of this region presenting its imaging characteristics through the most commonly available  techniques (MDCT, CBCT, MRI and US). In addition, two special chapters on angiography and micro-CT expand the limits of dentomaxillofacial imaging.\nThis comprehensive book will be an invaluable tool for radiologists, dentists, surgeons and ENT specialists in their training and daily practice.', 'Atlas of Dentomaxillofacial Anatomical Imaging', 'http://link.springer.com/book/10.1007/978-3-030-96840-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-96840-3.jpg', NULL, NULL, NULL),
(5950, 'Dr. Daniel J. MearaDr. Rajesh Gutta', '', '978-3-030-82598-0', 10850, 0, '2022', 'This book is a detailed guide to the identification and appropriate management of patients who represent a high risk when performing oral and maxillofacial surgery or the complex procedures that are increasingly attempted by general dental practitioners. Emphasis is also placed on evaluation of the medically compromised patient for outpatient anesthesia. The book is systematically divided into a series of chapters focusing on the medical conditions most commonly encountered in practice and on current treatment standards. Each chapter outlines evidence-based guidelines for evaluation of patients to establish whether they are suitable candidates for oral surgery. In addition, commonly encountered clinical management dilemmas are thoroughly explored. Lastly, this book will enable the provider to understand whether there is a need to seek medical clearance before proceeding. It will be an invaluable guide for both oral and maxillofacial surgeons and general dentists.', 'Oral and Maxillofacial Surgery for the Medically Compromised Patient', 'http://link.springer.com/book/10.1007/978-3-030-82598-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-82598-0.jpg', NULL, NULL, NULL),
(5951, 'Carlos ZarorRodrigo MariÃ±o', '', '978-3-030-96289-0', 10150, 0, '2022', 'This is the first known book on economic evaluations specifically geared to oral health professionals. The book serves as a starting point that explains the concepts and tools required for practitioners with little or no formal training or experience in economic evaluation to conduct such evaluations in oral health(care). It provides the foundation for applying economic evaluation principles to oral health programs as well as more advanced technical information for those interested in acquiring knowledge of health economics within the context of oral health care.\n\nIn the book, the authors describe the different types of economic evaluation and discuss their role and application in oral health care. Topics explored among the chapters include:\nWhy carry out an economic evaluation in oral health care?\nAspects of decision modelling for economic evaluation in oral health care\nInterpreting economic evaluation in oral health\nWorked examples in cost-effectiveness, cost-benefit, and cost-utility analyses\nAssessing the quality and usefulness of economic evaluation in oral health: a practical approach for clinicians\nUsing economic evaluations to inform decision-making in oral health: Transferability\nEconomic evaluation: uses and potential uses in oral health policy development\n\nIntroduction to Economic Evaluation in Oral Health Care has an applied orientation that emphasizes practical solutions to managing existing problems and situations in oral health care. As such, the book is essential reading for oral health professionals including dentists, oral health therapists, and dental hygienists, as well as students in the oral health professions. The text is also an appropriate and useful resource for other health practitioners and managers who are interested in enhancing their practical understanding of economic evaluation including health economists and otherhealth professionals and decision-makers.', 'Introduction to Economic Evaluation in Oral Health Care', 'http://link.springer.com/book/10.1007/978-3-030-96289-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-96289-0.jpg', NULL, NULL, NULL),
(5952, 'Roberto CavallaroCristina Colombo', '', '978-3-031-07715-9', 9770, 0, '2022', 'The core chapters are dedicated to mental disorders diagnosed according to the DSM V, and are organized in sub-chapters with key feature boxes and schemes that will allow the global comprehension of the mental disorder and its clinical management. The work includes also a general chapter on psychopathology and one on psychopharmacology presenting the practical information about suggested doses, side effects, drug interactions and warnings for the main psychotropics. The final chapter deals with forensic and legalaspects.\nFundamentals of Psychiatry for Health Care Professionals will appeal to a wide readership, from post graduate professionals who want to broaden their clinical knowledge of psychiatry to medical students and students of the health degree courses like Physiotherapy, Psychology, Nursing, or Dentistry.', 'Fundamentals of Psychiatry for Health Care Professionals', 'http://link.springer.com/book/10.1007/978-3-031-07715-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-07715-9.jpg', NULL, NULL, NULL),
(5953, 'Claire Teresa Lundy', '', '978-3-031-16321-0', 9770, 0, '2022', 'This short practical text uses a coaching approach to develop the reader’s interview skills. With increasing competition, doctors and healthcare professionals need to prepare well for success at interview. The author has successfully coached colleagues in the run-up to interviews using this approach. Readers will learn how to structure responses to reflect their personality, knowledge and experience. This approach encourages candidates to craft their responses in a compelling narrative that will help them stand out.\nHealthcare organisations are increasingly looking at assessment of values and behaviours as part of the recruitment process. This represents a shift from a more clinical competency-based approach and requires additional preparation for interview. This book will help coach clinicians to describe their own experience in this context.  \nThe author is a practicing clinician, coach and led development of a clinical leadership and quality improvementtraining program for doctors and dentists and training in the UK. This book is aimed at doctors and healthcare professionals in training positions and those moving to a new role.', 'The Medical Interview Coach', 'http://link.springer.com/book/10.1007/978-3-031-16321-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-031-16321-0.jpg', NULL, NULL, NULL),
(5954, 'Dr. Ki Beom KimDr. Reza MovahedDr. Raman K. MalhotraMD Jeffrey J. Stanley', '', '978-3-030-54146-0', 22730, 0, '2021', 'This book provides comprehensive information on the etiology, pathophysiology, medical implications, diagnosis, and surgical and nonsurgical treatment of obstructive sleep apnea (OSA). \nDivided into five parts, the book begins with principles and fundamentals of OSA and its diagnostic considerations. Subsequent parts then address non-surgical management, surgical management, and maxillomandibular advancements for OSA. Chapters seek to approach this common disorder from the viewpoint of multiple specialties, thereby promoting the development of a broad strategy for the evaluation and management of OSA patients that draws on each of them. \nAn invaluable reference, Management of Obstructive Sleep Apnea: An Evidence-Based, Multidisciplinary Textbook meets the needs of advanced dental and medical students, orthodontic, maxillofacial, ENT, neurology, and plastic surgery residents, and sleep medicine and pulmonary physicians.', 'Management of Obstructive Sleep Apnea', 'http://link.springer.com/book/10.1007/978-3-030-54146-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-54146-0.jpg', NULL, NULL, NULL),
(5955, 'Mark R. StevensShohreh GhasemiReza Tabrizi', '', '978-3-030-75750-2', 22730, 0, '2021', 'This book examines the latest technologies and developments in oral and maxillofacial surgery. It presents information in an easy-to-read format and meticulously details each surgical technique. \n \nThorough and accurate chapters comprehensively present procedures and treatments step-by-step procedures objectively. Each chapter follows a consistent format of which includes the scientific documentation of the procedure through clinical studies, objective benefits for the patient, detailed explanations of the procedure, levels of treatment complexity according to the SAC (simple -advanced complex) classification, and cost-effectiveness of the procedure for the patient and clinician. Extensive images, figures, and tables supplement select chapters to aid in visual learning. \n \nExtensive and unique, Innovative Perspectives in Oral and Maxillofacial Surgery is a vital tool for all dental specialists ranging from undergraduate students to established oral maxillofacial surgeons.', 'Innovative Perspectives in Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-75750-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-75750-2.jpg', NULL, NULL, NULL),
(5956, 'Dr. Enno Schmidt', '', '978-3-030-82804-2', 22730, 0, '2021', 'Diseases of the Oral Mucosa: Study Guide and Review presents an in depth overview of the latest diagnostic tools and management options available for diseases of the oral mucosa and is an ideal resource for trainee and practising dentists, dermatologists and stomatologists preparing to sit board examinations.', 'Diseases of the Oral Mucosa', 'http://link.springer.com/book/10.1007/978-3-030-82804-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-82804-2.jpg', NULL, 'popular_request', NULL),
(5957, 'Kaan Orhan', '', '978-3-030-62179-7', 16280, 0, '2021', 'This book offers a comprehensive review of the state of the art in Ultrasonography (USG) dentomaxillofacial imaging to help radiologists and dentists in their training and daily practice.\nThe book examines the relationship between clinical features, diagnosis, and choice of minimally invasive technique for a range of dentomaxillofacial disorders and provides information on post-treatment therapy. Accurate interpretation of indications for treatment is the cornerstone of success in medicine, and as such, the book explains how the selection of imaging technique is closely linked to clinical and diagnostic aspects and how recognition of this relationship forms the foundation for optimal outcomes. In addition to examining the various modalities, the book highlights the role of the latest USG imaging techniques. Further, it discusses in detail the pathology, treatment, and prognosis of common and rare diseases, as well as congenital/developmental malformations in the dentomaxillofacial, an area that is often underestimated and largely ignored by dentists.', 'Ultrasonography in Dentomaxillofacial Diagnostics', 'http://link.springer.com/book/10.1007/978-3-030-62179-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-62179-7.jpg', NULL, NULL, NULL),
(5958, 'MD Abdul Latif HamdanMD Robert Thayer SataloffProf. Valerie TrollingerProf. Mary J. Hawkshaw', '', '978-3-030-69109-7', 13020, 0, '2021', 'This volume provides an eloquent review of the anatomy and physiology of phonation, the work-up of patients with voice disorders, basic evaluation of wind instrument performance and dysfunction, and a full description of the most common skeletal and non-skeletal dentofacial anomalies, including their means of diagnosis and treatment. This is followed by a comprehensive review of literature on the vocal and acoustic features of affected patients, as well as the special considerations in wind instrumentalists. The effect of orthodontic therapy/ orthognathic surgery on voice, associated upper airway changes, and wind instruments performance is emphasized. The information provided in this book will heighten the patients’, therapists’, teachers’ and physicians’ awareness of the vocal characteristics and wind instrumentalists concerns often associated with these conditions.\nDentofacial Anomalies: Implications for Voice and Wind Instrument Performance is addressedto otolaryngologists, laryngologists, speech-language pathologists, voice teachers, professional voice users, wind instrumentalists, instrument teachers, arts medicine physicians, physical therapists, orthodontists and other dentists, as well as members of the general public who are concerned about their voices and or wind instrument playing.', 'Dentofacial Anomalies', 'http://link.springer.com/book/10.1007/978-3-030-69109-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-69109-7.jpg', NULL, NULL, NULL),
(5959, 'Prof. Dr. Dr. Ulrich Meyer', '', '978-3-030-46024-2', 11940, 0, '2021', 'This is the first volume in an interdisciplinary three-book series covering the full range of biological, clinical, and surgical aspects in the evaluation, diagnosis, and treatment of patients with craniofacial malformations. This volume opens by considering general topics such as developmental biology and disease classification and then examines in depth the biological basis of the various malformations, including craniosynostoses, cleft-lip and palate with complex orofacial clefts, branchio-oculo-facial syndromes, rare syndromes, soft tissue malformations, and dysgnathia. Psychological aspects, including psychological evaluation methods and therapies and quality of life issues, are then addressed. Finally, all relevant clinical, radiological, and genetic investigations are described and important diagnostic issues are explored. Featuring numerous high-quality illustrations, the book will be of high value for all clinicians, researchers, and postgraduate students who deal with these malformations. The accompanying two volumes describe treatment principles and present in an atlas manner all relevant surgical techniques in detail. The content of this multivolume set, written by the world’s leading research and clinical specialists in their discipline, represents therefore the recent intellect, experience, and state of this medical field.', 'Fundamentals of Craniofacial Malformations', 'http://link.springer.com/book/10.1007/978-3-030-46024-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-46024-2.jpg', NULL, NULL, NULL),
(5960, 'MD Robert RetiMD Damian Findlay', '', '978-3-030-48880-2', 9770, 0, '2021', 'The oral board exam for the American Board of Oral and Maxillofacial Surgery (ABOMS) can be intimidating to many surgeons due to the broad range of information one must know for the exam. However, while the examination guidelines provide a general outline of topics that may be covered, there is no true direction on how to prepare for it. Traditionally, candidates do so by using what are considered “underground” databanks, previous test questions, and power point presentations that run the gamut of commonly covered material. Until now, there have been no current comprehensive oral board review books available for the Oral and Maxillofacial Surgery boards. Oral Board Review for Oral and Maxillofacial Surgery fills that gap as the go-to resource for those attempting to successfully challenge the oral boards and for residents to polish up on their training.\n \nEdited and authored by top physicians in the field, this book is concise and easy to read, yet thorough with high yield information. An outline of the pertinent material is reviewed, and a patient work up is presented. Important questions to ask, signs to look for, and labs/images to order are included. It also includes tables and keywords that are typically mentioned on the exam and also offers explanations to some key points. Next are cases, which are presented in a question and answer format. As the case progresses, more complicated scenarios requiring management are presented. Lastly, complications are covered, which is the final section of each board scenario. Included are basic topics the surgeon needs to know, followed by topics that are nice to know, and numerous highly debated/complex questions that are discussed among candidates preparing for the exam. It should be noted that the authors are not privy to any inside information about the exam. What is presented is material candidates that have successfully passed the exam feel is important to know. This book is not endorsed by American Association of Oral ', 'Oral Board Review for Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-48880-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-48880-2.jpg', NULL, NULL, NULL);
INSERT INTO `book` (`id`, `author`, `edition`, `isbn`, `price`, `quantity`, `year`, `description`, `book_title`, `url`, `cover_image`, `publisher`, `status`, `created_at`) VALUES
(5961, 'Prof. Julio Acero', '', '978-3-030-74322-2', 9770, 0, '2021', 'This book provides a comprehensive review of the new technologies that are having a tremendous impact on the complex field of craniomaxillofacial reconstructive surgery. Readers will find detailed information on the technologies themselves, their indications, and their benefits. The coverage encompasses the use of biomaterials and tissue engineering, virtual planning and CAD/CAM techniques, the various applications of computer-assisted surgery, and intraoperative navigation. Robotic surgery, endoscopic approaches, and piezoelectric surgery are each addressed within individual chapters. New developments in craniofacial pediatric surgery are discussed, and the book concludes by examining the present and future of facial transplantation. The text is supported by numerous high-quality color illustrations, and the team of authors comprises prestigious international leaders in the specialty. The book will be of value for all who are interested in learning about the innovations and developments that are reducing morbidity and improving outcomes in patients who require craniomaxillofacial reconstruction.', 'Innovations and New Developments in Craniomaxillofacial Reconstruction', 'http://link.springer.com/book/10.1007/978-3-030-74322-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-74322-2.jpg', NULL, NULL, NULL),
(5962, 'Priv. Doz. Kristian KnihaProf. Dr. Dr. Karl Andreas SchlegelProf. Dr. Dr. Heinz Kniha', '', '978-3-030-75216-3', 9230, 0, '2021', 'This book is an accurate introduction to guided implantology. As practitioners with many years of experience, the authors present an important basis for scientific findings and a valid decision-making aid for digital oral surgery.\n\nOverall, this work appeals to beginners and experts alike.', 'Guided Surgery in Implantology', 'http://link.springer.com/book/10.1007/978-3-030-75216-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-75216-3.jpg', NULL, NULL, NULL),
(5963, 'MD Jong-Woo ChoiPh.D. Jang Yeol Lee', '', '978-981-15-7541-9', 9230, 0, '2021', 'This book is a comprehensive guide to the surgery-first orthognathic approach for patients with malocclusion and skeletal disharmony, which has been successfully applied by the authors in their practices over the past 15 years. The approach breaks with the time-tested principles of traditional orthognathic surgery in that corrective bone surgery is performed first, without the removal of dental compensations, followed by orthodontic finishing. All aspects are covered with the aid of numerous illustrations, the aim being to provide surgeons with a systematic educational tool that will enable them to introduce the approach into their own practice. In addition, the book addresses one of the hot issues in orthodontics, occlusal plane-altering orthognathic surgery, in which surgical modification of the occlusal plane is employed to treat various types of dentofacial deformity and improve facial proportions. This promises to become a very powerful tool in modern orthognathic surgery.', 'The Surgery-First Orthognathic Approach', 'http://link.springer.com/book/10.1007/978-981-15-7541-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-981-15-7541-9.jpg', NULL, NULL, NULL),
(5964, 'Prof. Lobat TayebiDr. Reza MasaeliKavosh Zandsalimi', '', '978-3-030-77787-6', 6790, 0, '2021', 'This book is a comprehensive guide to 3D printing and 3D bioprinting methods and their application in oral and maxillofacial surgeries. Among the 3D printing methods considered are fused deposition modeling, selective laser sintering, photopolymer jetting, powder binder printing, and stereolithography, while the coverage of 3D bioprinting encompasses inkjet, microextrusion, and laser techniques. In each case, the relevance of the technique to oral and maxillofacial surgery is explained. In addition, the available inks and bioinks for 3D printing are reviewed. The roles of soft and hard tissue printing in oral and maxillofacial tissue engineering and the use of 3D printing in multi- and interfacial tissue engineering are then examined in depth. The particular value of 3D printing in the treatment of critically sized defects is discussed separately. Finally, up-to-date information is provided on guided tissue/bone regeneration using 3D printing. The book will be of interest to both oraland maxillofacial surgeons and biomedical engineers.', '3D Printing in Oral & Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-77787-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-77787-6.jpg', NULL, NULL, NULL),
(5965, 'Eduardo Santini-AraujoRicardo K. KalilFranco BertoniYong-Koo Park', '', '978-3-030-28315-5', 24850, 0, '2020', 'This updated second edition of a successful book provides essential, internationally applicable information in the area of bone and joint pathology with emphasis on practical diagnostic aspects, including many illustrations: roentgenograms, CT-scans, MRI, scintigraphies, as well as pictures of gross surgical specimens and microphotographs, immunohistochemical reactions and genomics. Information on histopathological and molecular diagnosis, and basic therapeutic guidelines are provided. \nTumors and Tumor-Like Lesions of Bone provides day-to-day assistance togeneral and specialized surgical pathologists, radiologists, orthopedic, head and neck and dental surgeons, oncologists and rheumatologists.', 'Tumors and Tumor-Like Lesions of Bone', 'http://link.springer.com/book/10.1007/978-3-030-28315-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-28315-5.jpg', NULL, NULL, NULL),
(5966, 'Paola Pasquali', '', '978-3-030-24544-3', 18450, 0, '2020', 'This book explains how medical photography is part of the workflow in many specialties: it is needed for registries, to preserve information, for follow up, second opinion and teaching, among others. The book gathers information on this field, providing valuable practical tips for those that have never used photography for medical uses as well as those who use it regularly. Covering specialities ranging from dermatology, plastic surgery, dentistry, ophthalmology and endoscopy to forensic medicine, specimen photography and veterinary medicine, it highlights standardization for each procedure and relevance to ethical, patients’ perception of medical photography, cybersecurity and legal aspects. The book also presents practical sections explaining how to organize a photographic file, coding, reimbursement, compliance, use of social media and preservation as well as in depth concepts on sharp focus on blurred vision. This volume will appeal to all clinicians and practitioners interested inacquiring a high level of technical skill in medical photography.', 'Photography in Clinical Medicine', 'http://link.springer.com/book/10.1007/978-3-030-24544-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-24544-3.jpg', NULL, NULL, NULL),
(5967, 'Dr. Stefan StÃ¼bingerDr. Florian KlÃ¤mpflProf. Dr. Michael SchmidtProf. Dr. Dr. Hans-Florian Zeilhofer', '', '978-3-030-29604-9', 11940, 0, '2020', 'This book provides surgeons with important insights into laser technologies as well as a sound understanding of their current and potential applications within oral and maxillofacial surgery and related disciplines. The opening chapters focus on the relevant physical background, the technology of the typically used lasers, laser–tissue interactions, and the treatment systems. Detailed information is then provided on the various established applications of laser treatments, including in relation to skin and mucosa and the dental hard tissues and bone. Special applications are also described, for example with respect to periodontal surgery, peri-implantitis therapy, photodynamic treatment, holography and additive manufacturing. The book closes by examining technologies that will soon be available for application in hospitals, topics which are currently the subject of research, and laser safety. Beyond surgeons, the book will be of value for engineers and scientists working in the field of medical engineering using lasers.', 'Lasers in Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-030-29604-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-29604-9.jpg', NULL, NULL, NULL),
(5968, 'Tiziana RobbaCarlotta TanteriGiulia Tanteri', '', '978-3-030-25421-6', 9770, 0, '2020', 'This book is the outcome of a fruitful, long-standing cooperation between expert radiologists and clinicians, and explains the most relevant features and technical requirements that are needed to optimally conduct and assess MR examinations for temporomandibular joint (TMJ) pathologies. TMJ conditions are increasingly gaining attention, as the underlying diseases involved can vary considerably and be difficult to diagnose. Similarly, several imaging sub-specialties (e.g. dental radiology, neuroradiology, and musculoskeletal radiology) now find themselves dealing with the temporomandibular joints. \nThe authors provide essential information on TMJ anatomy, dynamics, function and dysfunction. Correlations between clinical aspects and MRI findings are discussed and guidance for the correct interpretation of results is offered. Special findings that are helpful for differential diagnosis (arthritis, osteochondroma, synovial chondromatosis) are also examined. Given its extensive and varied coverage, the book offers a valuable asset for radiologists, dentists, gnathologists, maxillofacial surgeons, orthodontists and other professionals seeking a thorough overview of the subject', 'MRI of the Temporomandibular Joint', 'http://link.springer.com/book/10.1007/978-3-030-25421-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-25421-6.jpg', NULL, NULL, NULL),
(5969, 'Prof. Kaan Orhan', '', '978-3-030-16641-0', 9230, 0, '2020', 'This book focuses on applications of micro CT, CBCT and CT in medicine and engineering, comprehensively explaining the basic principles of these techniques in detail, and describing their increasing use in the imaging field.\nIt particularly highlights the scanning procedure, which represents the most crucial step in micro CT, and discusses in detail the reconstruction process and the artifacts related to the scanning processes, as well as the imaging software used in analysis.\nWritten by international experts, the book illustrates the application of micro CT in different areas, such as dentistry, medicine, tissue engineering, aerospace engineering, geology, material engineering, civil engineering and additive manufacturing.\nCovering different areas of application, the book is of interest not only to specialists in the respective fields, but also to broader audience of professionals working in the fields of imaging and analysis, as well as to students of the different disciplines.', 'Micro-computed Tomography (micro-CT) in Medicine and Engineering', 'http://link.springer.com/book/10.1007/978-3-030-16641-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-16641-0.jpg', NULL, NULL, NULL),
(5970, 'Anastassia Kossioni', '', '978-3-030-41468-9', 9230, 0, '2020', 'This book provides basic knowledge and skills for non-dental healthcare practitioners, helping them recognize the importance of oral health, perform initial oral health assessments, consult dentists when necessary, and offer preventive advice and counseling. As people age, they tend to refrain from routine dental care, while the number of consultations with non-dental healthcare providers (physicians, nurses, pharmacists, physician assistants, physical therapists, occupational therapists etc.) increases. However, few healthcare providers are adequately trained to assess oral problems.\nThe relevance of this book is underscored by the recently published European policy recommendations on oral health in older adults by the European College of Gerodontology and the European Geriatric Medicine Society, which highlight the importance of the active involvement of non-dental primary care practitioners in oral health assessment and promotion. These two respected European Societies have identified a significant gap in education, practice and health policies and described the necessary action plans. This book helps to fill the educational gap identified in the recommendations and will be an invaluable tool for all healthcare providers working with older people.', 'Gerodontology Essentials for Health Care Professionals', 'http://link.springer.com/book/10.1007/978-3-030-41468-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-41468-9.jpg', NULL, NULL, NULL),
(5971, 'Prof. Nejat ErverdiProf. Melih Motro', '', '978-3-030-49781-1', 8680, 0, '2020', 'The second edition of this comprehensive book describes a new alveolar distraction osteogenesis method that offers important advantages and can be used for the treatment of various orthopedic abnormalities and congenital malformations. Detailed guidance is provided on the selection of suitable candidates for alveolar distraction, including those with cleft lip and palate, with severe bone defects, skeletal class II malocclusions and cystic lesions involving the alveolus. All aspects of treatment using the ArchWise distraction appliance are then covered, including technical preparation, surgical set-up and osteotomies, docking site surgery, orthodontic finishing, implant placement and prosthetic restorations. Detailed information on the principles of distraction osteogenesis, bone histology and molecular interactions during the procedure is also provided. The book concludes with helpful case presentations covering different scenarios in which treatment with alveolar distractionosteogenesis is advisable.', 'Alveolar Distraction Osteogenesis', 'http://link.springer.com/book/10.1007/978-3-030-49781-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-49781-1.jpg', NULL, NULL, NULL),
(5972, 'Alex M. GreenbergMD Rainer Schmelzeisen', '', '978-1-4939-1529-3', 22680, 0, '2019', 'This in-depth revision of the successful first edition is one of the only books of its kind to cover the full range of craniomaxillofacial reconstructive and corrective bone surgery. This evolving field has a large number of contributions by worldwide clinicians covering new developments, especially in biomaterials, digital technologies, virtual surgical planning, patient specific implants, and navigation. These topics appeal to Oral and Maxillofacial Surgeons, Plastic Surgeons, ENT/Head and Neck Surgeons, and Neurosurgeons. Complete with updates on popular topics from the first edition, such as advanced jaw reconstruction with stem cells and tissue engineering, wide varieties of microvascular flaps, orthognathic surgery, endoscopic skull base surgery, dental implantology, craniofacial surgery and facial allotransplantation.', 'Craniomaxillofacial Reconstructive and Corrective Bone Surgery', 'http://link.springer.com/book/10.1007/978-1-4939-1529-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4939-1529-3.jpg', 'Springer', NULL, NULL),
(5973, 'Prof. Onur KadiogluProf. G. FrÃ¤ns Currier', '', '978-3-030-00722-5', 15190, 0, '2019', 'This book is designed to serve as an up-to-date reference on the use of cone-beam computed tomography for the purpose of 3D imaging of the craniofacial complex. The focus is in particular on the ways in which craniofacial 3D imaging changes how we think about conventional diagnosis and treatment planning and on its clinical applications within orthodontics and oral and maxillofacial surgery. Emphasis is placed on the value of 3D imaging in visualizing the limits of the alveolar bone, the airways, and the temporomandibular joints and the consequences for treatment planning and execution. The book will equip readers with the knowledge required in order to apply and interpret 3D imaging to the benefit of patients. All of the authors have been carefully selected on the basis of their expertise in the field. In describing current thinking on the merits of 3D craniofacial imaging, they draw both on the available scientific literature and on their own translational research findings.', 'Craniofacial 3D Imaging', 'http://link.springer.com/book/10.1007/978-3-030-00722-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-00722-5.jpg', NULL, NULL, NULL),
(5974, 'Prof. Ingrid Rozylo-KalinowskaProf. Kaan Orhan', '', '978-3-319-99468-0', 15190, 0, '2019', 'This superbly illustrated book is designed to meet the demand for a comprehensive yet concise source of information on temporomandibular joint (TMJ) imaging that covers all aspects of TMJ diagnostics. After introductory chapters on anatomy, histology, and the basics of radiological imaging, detailed guidance is provided on the use and interpretation of radiography, CT, CBCT, ultrasound, MRI, and nuclear medicine techniques. Readers will find clear presentation of the imaging findings in the full range of TMJ pathologies, from intrinsic pathological processes to invasion by lesions of the temporal bone and mandibular condyle. Careful attention is also paid to the technical issues confronted when using different imaging modalities, and the means of resolving them. The role of interventional radiology is examined, and consideration given to the use of arthrography and arthrography-guided steroid treatment. In addition, an overview of recent advances in research on TMJ diagnostics is provided. Imaging of the Temporomandibular Joint has been written by an international team of dedicated authors and will be of high value to clinicians in their daily practice.', 'Imaging of  the Temporomandibular Joint', 'http://link.springer.com/book/10.1007/978-3-319-99468-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-99468-0.jpg', NULL, NULL, NULL),
(5975, 'S. Thaddeus ConnellyGianluca Martino TartagliaRebeka G. Silva', '', '978-3-319-99909-8', 15190, 0, '2019', 'This book is a comprehensive, state of the art guide to the contemporary surgical treatment of temporomandibular disorders (TMDs) that will help to compensate for the frequent lack of experience and inadequate training among health professionals who encounter patients with jaw joint problems. The opening section discusses the evolution of modern surgical management of TMDs, TMD diagnosis for surgical candidates, as well as anatomic pathways. Surgical procedures are then described and illustrated, with detailed coverage of total temporomandibular joint replacement and also other procedures such as surgical arthroscopy, intraoral vertical ramus osteotomy, discectomy, and arthroplasty. The volume closes by examining the future of the field, including the use of bioengineered constructs. Complementary volumes are devoted to anatomy, pathophysiology, evaluation, and diagnosis and to the nonsurgical treatment of TMDs, respectively. Each volume will be of high value for the multidisciplinary team necessary for successful management of TMDs, including dentists, surgeons, primary care doctors, pain doctors, and allied health professionals.', 'Contemporary Management of Temporomandibular Disorders', 'http://link.springer.com/book/10.1007/978-3-319-99909-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-99909-8.jpg', NULL, NULL, NULL),
(5976, 'Prof. Giorgio De SantisProf. Peter G. CordeiroProf. Luigi Chiarini', '', '978-3-030-10684-3', 14110, 0, '2019', 'This atlas deals with the standard technique used for reconstructing the mandible and the maxilla - the fibula flap. The reader will find useful information on all issues that are important in the surgical procedure, including the use of CAD-CAM technology (Computer Assisted Technology), bone synthesis and flap modelling. The editors draw on their 30 years of experience to provide a step-by-step description of this surgical procedure. With the help of numerous illustrations, the reader will learn the technical, functional and aesthetic developments since 1989 when this technique was first described.', 'Atlas of Mandibular and Maxillary Reconstruction with the Fibula Flap', 'http://link.springer.com/book/10.1007/978-3-030-10684-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-10684-3.jpg', NULL, NULL, NULL),
(5977, 'Nasim Fazel', '', '978-3-030-10863-2', 14110, 0, '2019', 'This book provides a comprehensive overview of oral signs of a broad spectrum of systemic diseases including gastrointestinal, hematologic, and endocrine, in addition to infectious, nutritional, autoimmune, genetic and connective tissue diseases. An overview of associated key signs and salient features to look for on oral exam is provided as well as other clinical manifestations, differential diagnoses, and treatment recommendations.  The mouth is an important anatomical location with a role in many critical physiologic processes that are frequently involved in conditions that affect the skin or other organ systems. In many instances, oral manifestations of a disease precede the appearance of other stigmata. Therefore, early recognition of oral signs and symptoms associated with underlying systemic diseases can be invaluable to the clinician in establishing a diagnosis and prompt initiation of therapy. This book, written for dermatologists, dentists, otolaryngologists, and oralmedicine specialists, offers a structured approach to the therapy and management of diseases affecting the oral mucosa.', 'Oral Signs of Systemic Disease', 'http://link.springer.com/book/10.1007/978-3-030-10863-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-10863-2.jpg', NULL, NULL, NULL),
(5978, 'S. Thaddeus ConnellyGianluca Martino TartagliaRebeka G. Silva', '', '978-3-319-99912-8', 14110, 0, '2019', 'This book is a comprehensive, state of the art guide to the contemporary non-surgical treatment of temporomandibular disorders (TMDs) that will help to compensate for the frequent lack of experience and inadequate training among health professionals who encounter patients with jaw joint problems. After an opening section outlining special considerations relating to bruxism and trauma in TMDs, medical management and dental treatment are explained in detail, with coverage of various perspectives such as those of the orthodontist and prosthodontist. Psychiatric considerations and adjunctive therapies are also thoroughly discussed and the importance of a team approach to the management of temporomandibular disorders is highlighted. Complementary volumes are devoted to anatomy, pathophysiology, evaluation, and diagnosis and to total temporomandibular joint replacement and other surgical procedures, respectively. Each book will therefore be of high value for the multidisciplinary team necessary for successful management of TMDs, including dentists, surgeons, primary care doctors, pain doctors, and allied health professionals.', 'Contemporary Management of Temporomandibular Disorders', 'http://link.springer.com/book/10.1007/978-3-319-99912-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-99912-8.jpg', NULL, NULL, NULL),
(5979, 'S. Thaddeus ConnellyGianluca Martino TartagliaRebeka G. Silva', '', '978-3-319-99915-9', 14110, 0, '2019', 'This book is a comprehensive, state of the art guide to the contemporary diagnosis of temporomandibular disorders (TMDs) that will help to compensate for the frequent lack of experience and inadequate training among health professionals who encounter patients with jaw joint problems. The opening section describes the whole patient philosophy essential for treatment success, examines ethical and legal considerations, and discusses all aspects of anatomy. Pathophysiology, clinical assessment, and imaging evaluation, including by means of modern MR imaging and CBCT, are then considered in detail. Finally, the diagnostic criteria for the full range of TMDs are thoroughly explained and the urgent need to appreciate temporomandibular disorders as the chronic pain conditions they are is addressed. Complementary volumes are devoted to non-surgical treatment of TMDs and to total temporomandibular joint replacement and other surgical procedures, respectively. Each book will be of high value forthe multidisciplinary team necessary for successful management of TMDs, including dentists, surgeons, primary care doctors, pain doctors, and allied health professionals.', 'Contemporary Management of Temporomandibular Disorders', 'http://link.springer.com/book/10.1007/978-3-319-99915-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-99915-9.jpg', NULL, NULL, NULL),
(5980, 'MD Elie M. FerneiniMichael T. Goupil', '', '978-3-030-22371-7', 10850, 0, '2019', 'This book is a comprehensive, step-by-step guide to maxillofacial surgical procedures typically performed in an office setting. It comprises three sections, the first of which provides an overview of general and basic perioperative topics such as medical and facial assessment, laboratory indications, local anesthesia, and oral and parenteral sedation.  In the second section, a wide range of dentoalveolar procedures are described in detail. The final section is devoted to maxillofacial cosmetic procedures. Here, readers will find stepwise guidance on scar revision, chemical peel, laser resurfacing, dermabrasion, use of neuromodulators and fillers, neck procedures, blepharoplasty, and hair transplant surgery. The book is written by acknowledged experts and is multi-institutional and multispecialty based. It will meet the needs of multiple surgical professionals, including oral and maxillofacial surgeons, plastic surgeons, otolaryngologists, cosmetic surgeons, dentists, and medical and dental students. Health care providers will also be able to use the book as a resource to expand their knowledge on common maxillofacial surgical procedures.', 'Office-Based Maxillofacial Surgical Procedures', 'http://link.springer.com/book/10.1007/978-3-030-22371-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-22371-7.jpg', NULL, NULL, NULL),
(5981, 'Prof. Khalid Rehman HakeemWaseem Mohammed AbdulMohd Muzzammil HussainSyed Shoeb Iqbal Razvi', '', '978-3-030-04336-0', 5810, 0, '2019', 'Oral health loss is one of the major problems existing all over the world and is one of the top causes of death when unmanaged. The oral cavity is home to numerous pathogenic microorganisms, some of which are responsible for the progression and development of various systemic diseases such as cancer, diabetes and myocardial infarction. Worldwide, 60–90% of school children and nearly 100% of adults have dental cavities, often leading to pain and discomfort. There are implications for the global economy as well, due to the continuous burden of investing resources to maintain oral hygiene. Not surprisingly, developing countries are disproportionally affected.  There is thus an urgent need to develop economical solutions for the treatment of oral diseases. The trend of exploring plants or plant-derived compounds for the prevention and cure of death-causing diseases is on the rise. The use of traditional medicine for oral diseases is an ancient practice in which medicinal herbs playa major role. Medicinal plants have minimal side effects and no denigrating properties. Accordingly the use of medicinal plants to curtail oral pathogens has been reported by a number of studies.\nThe present book updates the issues related to oral health, oral diseases and the role of medicinal plants in overcoming orally-derived health problems. We also highlight the knowledge gaps in oral health related problems with medicinal plants as one of the solutions. Our ultimate goal is to encourage future research and application of medicinal plants for economical and efficient treatment of oral diseases.', 'Oral Health and Herbal Medicine', 'http://link.springer.com/book/10.1007/978-3-030-04336-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-030-04336-0.jpg', NULL, NULL, NULL),
(5982, 'MD William C. ScarfeMD Christos Angelopoulos', '', '978-3-319-62061-9', 36780, 0, '2018', 'The book provides a comprehensive description of the fundamental operational principles, technical details of acquiring and specific clinical applications of dental and maxillofacial cone beam computed tomography (CBCT). It covers all clinical considerations necessary for optimal performance in a dental setting. In addition overall and region specific correlative imaging anatomy of the maxillofacial region is described in detail with emphasis on relevant disease. Finally imaging interpretation of CBCT images is presented related to specific clinical applications. This book is the definitive resource for all who refer, perform, interpret or use dental and maxillofacial CBCT including dental clinicians and specialists, radiographers, ENT physicians, head and neck, and oral and maxillofacial radiologists.', 'Maxillofacial Cone Beam Computed Tomography', 'http://link.springer.com/book/10.1007/978-3-319-62061-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-62061-9.jpg', NULL, NULL, NULL),
(5983, 'Prof. Qianming ChenDr. Xin Zeng', '', '978-981-13-0286-2', 16280, 0, '2018', 'This book includes real-time photographical recording and panoramic summary of 105 cases with oral mucosal diseases along with their diagnosis and management. This book reflects the characteristic clinical manifestations through images of each case presented. In addition to the medical history, examination, diagnosis, pathology and management of each case, a comprehensive commentary is introduced in the end of each chapter with an emphasis on the normative clinical train of thoughts and guidelines.', 'Case Based Oral Mucosal Diseases', 'http://link.springer.com/book/10.1007/978-981-13-0286-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-981-13-0286-2.jpg', NULL, NULL, NULL),
(5984, 'Keyvan Nouri', '', '978-3-319-76220-3', 14110, 0, '2018', 'Along with its sister dermatologic volume, this comprehensive textbook of laser technology covers the use of lasers in cardiac procedures, control of intraocular pressure, urological procedures, neurological use, dentistry, gynaecology and surgical applications. Chapters are formatted in an easy to follow format with clear concise sections with bulleted summaries to highlight key points.\n\n\nLasers in Dermatology and Medicine: Dental and Medical Applications provides detailed explanations of when lasers can be of use how to use them across a range of medical disciplines. Clinically relevant examples are provided along with relevant images and summary boxes to highlight key points.  It therefore provides a critical resource on the applications and use of lasers across medicine for both the trainee and trained clinician.', 'Lasers in Dermatology and Medicine', 'http://link.springer.com/book/10.1007/978-3-319-76220-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-76220-3.jpg', NULL, NULL, NULL),
(5985, 'Prof. Elie M. FerneiniProf. Jeffrey D. Bennett', '', '978-3-319-58868-1', 13020, 0, '2018', 'This book is designed to guide the practitioner in the medical and anesthetic management of the maxillofacial surgery patient, serving as a comprehensive, up-to-date resource that will assist in patient work-up and response to any medical problem. It is divided into four sections that provide an overview of general and basic topics relevant to perioperative assessment, explain the assessment and management of diverse medical issues and co-morbidities, discuss the perioperative, pharmacological, and supportive management of maxillofacial treatment,  and identify potential complications and their management. All of the authors have been carefully selected for their expertise in the topics that they discuss. While the book will be especially valuable for oral and maxillofacial surgeons, it will also be highly relevant for multiple other health care providers, including dentists, dental specialists, dental hygienists, otolaryngologists, plastic and reconstructive surgeons, medical residents, nurses, and physician assistants.', 'Perioperative Assessment of the Maxillofacial Surgery Patient', 'http://link.springer.com/book/10.1007/978-3-319-58868-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-58868-1.jpg', NULL, NULL, NULL),
(5986, 'Prof. Elie M. FerneiniDr. Charles L. CastiglioneDr. Mohammad Banki', '', '978-3-319-58756-1', 10850, 0, '2018', 'This book is designed to offer practitioners clear, up-to-date guidance on the management of complications associated with maxillofacial cosmetic surgery. The first section provides a detailed overview of general topics relating to cosmetic surgery patients, including assessment, anesthesia and medical complications, wound healing, postoperative infection, pain management, and medicolegal issues. The second section then discusses the nature and management of the complications associated with each maxillofacial cosmetic surgery procedure, from laser treatment and use of neuromodulators and soft tissue fillers to orthognathic surgery, rhinoplasty, neck procedures, rhytidectomy, genioplasty, and facial implants. Complications in Maxillofacial Cosmetic Surgery is multi-authored, multi-institutional, and multi-specialty based. It will be of value for a range of health care providers who practice in the head and neck area, including oral and maxillofacial surgeons, otolaryngologists, plastic and reconstructive surgeons, dermatologists, and cosmetic surgeons.', 'Complications in Maxillofacial Cosmetic Surgery', 'http://link.springer.com/book/10.1007/978-3-319-58756-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-58756-1.jpg', NULL, NULL, NULL),
(5987, 'Dr. Nigel Shaun Matthews', '', '978-3-319-62652-9', 10850, 0, '2018', 'This book provides a comprehensive overview of dislocation of the temporomandibular joint (TMJ), covering all relevant aspects, from aetiology and diagnosis to management. The treatment-oriented chapters describe nonsurgical, surgical and arthroscopic interventions, and the book closes by examining the role of total alloplastic reconstruction of the TMJ in patients with chronic jaw joint dislocation. Each chapter commences with a summary of key points and the clearly written text is supported by numerous clinical photographs, as well as by videos to which the reader will have online access. All of the authors are recognized experts in the topics that they discuss.\n\nDislocation of the TMJ constitutes a medical emergency since prompt treatment is required in order to prevent the harmful sequelae that may arise once spasm of the muscles of mastication has become established, preventing return of the condyle into the glenoid fossa. If the condition is left untreated, radical corrective surgery may be required to restore jaw function and eliminate pain. In presenting state of the art knowledge on TMJ dislocation, this book will be of value for all involved in the management of the condition.', 'Dislocation of the Temporomandibular Joint', 'http://link.springer.com/book/10.1007/978-3-319-62652-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-62652-9.jpg', NULL, NULL, NULL),
(5988, 'Prof. Oded Nahlieli', '', '978-3-662-54592-8', 10850, 0, '2018', 'Minimally invasive techniques, designed to reduce morbidity and risk while simultaneously improving outcomes, are increasingly being used in oral and maxillofacial surgery. This book covers the most recent technological developments and the advanced techniques used when performing such minimally invasive surgery in patients with common and rare oral and maxillofacial pathologies. The relevant basic science is reviewed, but the principal focus is on the surgical techniques themselves. These are described step by step with the aid of numerous superb color illustrations that will help the clinician to gain a full understanding of the technology and the procedures. In addition, still emerging techniques of endoscopy, navigation, and minimally invasive surgery are well covered. This text will be a premier resource for physicians who diagnose and treat oral and maxillofacial pathologies and injuries.', 'Minimally Invasive Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-662-54592-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-54592-8.jpg', NULL, NULL, NULL),
(5989, 'Dr. Nivaldo AlonsoDr. Cassio Eduardo Raposo-Amaral', '', '978-3-319-63290-2', 9770, 0, '2018', 'The aim of this book is to discuss cleft lip and palate deformities in a comprehensive way, presenting it from the basics to the most clinically and surgically relevant issues. First, the basic concepts of embryology and pathogenesis of the facial deformities will be discussed. Special attention will be paid to the genetics underlying this condition. Following that, basic principles of surgical treatment through the most recent advances in the field will be presented, along with most important evidences from the literature and the personal experience of the editors and authors. \nCleft Lip and Palate Treatment presents the state of the art and advances in the field and is intended to serve as a comprehensive guide for a broad audience. All the specialties involved in the comprehensive care of these craniofacial deformities will be presented in this book.', 'Cleft Lip and Palate Treatment', 'http://link.springer.com/book/10.1007/978-3-319-63290-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-63290-2.jpg', NULL, NULL, NULL),
(5990, 'Allen M. KhakshooyPh.D. Francesco Chiappelli', '', '978-3-662-57437-9', 9770, 0, '2018', 'There is an ever-increasing emphasis on evidence-based medicine that is distinguished by systematic crafting of the patient-centered research question, detailed literature searches, and careful appraisal of the resulting evidence. The consensus that ultimately emerges must then be applied in specific clinical settings, and it is to this process that translational effectiveness analysis refers. This portable and easy-to-use handbook is intended as a practical teaching guide on translational effectiveness for students and clinicians. Specifically, it will serve as a primer on patient-centered outcomes research methodology in the health sciences and explain how to acquire and understand the fundamental data that determine which reports are valued as the “best available” evidence. It presents an accessible and readily intelligible set of principles which doctors, dentists, nurses, and insurance carriers will be able to use in the process of health care-related decision-making.', 'Practical Biostatistics in Translational Healthcare', 'http://link.springer.com/book/10.1007/978-3-662-57437-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-57437-9.jpg', NULL, NULL, NULL),
(5991, 'Gwen Swennen', '', '978-3-662-47389-4', 17360, 0, '2017', 'This color atlas and manual provides clinicians with systematic, standardized, but also individualized step-by-step guidance on 3D virtual diagnosis, treatment planning, and outcome assessment in patients undergoing orthognathic surgery for maxillofacial deformities. Drawing on 20 years of experience, the authors elucidate the clinical potential of the approach while also highlighting current pitfalls and limitations. The opening two chapters discuss the 3D imaging workflow and its integration into daily clinical routine and comprehensively describe cone-beam CT virtual diagnosis. The stepwise 3D virtual planning of orthognathic surgery and transfer of the 3D virtual treatment plan to the patient in the operating room are then thoroughly explained, and the unprecedented potential of 3D virtual evaluation of treatment outcome, documented.  Finally, after provision of all this essential background information, the closing chapter illustrates the application of the 3D virtual approach in different types of maxillofacial deformity. Orthodontists and orthognathic and orthofacial surgeons will find 3D Virtual Treatment Planning of Orthognathic Surgery to be a superb guide and resource.', '3D Virtual Treatment Planning of Orthognathic Surgery', 'http://link.springer.com/book/10.1007/978-3-662-47389-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-47389-4.jpg', 'Springer London, Limited', NULL, NULL),
(5992, 'Gary F. Bouloux', '', '978-3-319-51241-9', 14110, 0, '2017', 'This book provides detailed guidance on the recognition and treatment of the complications most frequently encountered in patients who undergo temporomandibular joint surgery. Evidence-based guidelines are referred to whenever possible, and when such guidelines are lacking, the preferred current approaches to diagnosis and management are described. In addition, the pathophysiology of each complication is discussed and advice offered on how to ensure that the correct surgical procedure is chosen for the individual patient, thereby minimizing the risk of complications. Illustrative cases are included to further highlight key points. The authors are experienced surgeons and pioneers in the field of temporomandibular joint surgery. Complications of Temporomandibular Joint Surgery will be of value for all who work in this technically very challenging field and regularly have to deal with the issues posed by a difficult patient population and the risk of suboptimal outcomes.', 'Complications of Temporomandibular Joint Surgery', 'http://link.springer.com/book/10.1007/978-3-319-51241-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-51241-9.jpg', NULL, NULL, NULL),
(5993, 'Prof. Moni Abraham Kuriakose', '', '978-3-319-14911-0', 11940, 0, '2017', 'This is the first of four volumes that together offer an authoritative, in-depth reference guide covering all aspects of the management of oral cancer from a multidisciplinary perspective and on the basis of a strong scientific foundation. This volume, on tumor biology, epidemiology, etiology, emerging role of cancer stem cells and prevention of oral cancer, opens by discussing oral carcinogenesis in general and the role of particular carcinogens and human papillomavirus. Global epidemiology and changes in disease prevalence are then addressed. Up-to-date information is provided on emerging cancer biomarkers, and the biologic basis of personalized therapy is explained. Histopathological features of malignant and premalignant neoplasms and their relevance to management are described. Further chapters focus on the current status of chemoprevention, the management of oral submucous fibrosis, and the value of various diagnostic adjuncts. The volume concludes by critically evaluating theefficacy of oral screening methods.\nVolume 1: Biology, Epidemiology, Etiology, and Prevention\nVolume 2: Diagnosis and Management\nVolume 3: Oral and Maxillofacial Reconstructive Surgery\nVolume 4: Rehabilitation and Supportive Care', 'Contemporary Oral Oncology', 'http://link.springer.com/book/10.1007/978-3-319-14911-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-14911-0.jpg', 'Springer London, Limited', NULL, NULL),
(5994, 'Ph.D. Ala-Eddin Al Moustafa', '', '978-3-319-48054-1', 10850, 0, '2017', 'This book aims to provide the reader with a complete understanding of the development of oral cancer by explaining the role of a wide variety of implicated risk factors and identifying their gene targets and key regulators. Some of the discussed risk factors are well known, including smoking, alcohol, betel quid chewing, and oncoviruses such as high-risk human papillomaviruses and Epstein-Barr virus; however, careful attention is also paid to less widely recognized factors, such as Qat chewing and yerba Mate consumption. The book concludes by describing and evaluating the most important strategies currently available for the prevention of oral carcinogenesis in humans. In presenting the most up-todate research and knowledge on these topics, this book will serve as a valuable source of up-to-date information for oncologists, cancer scientists, and medical students.', 'Development of Oral Cancer', 'http://link.springer.com/book/10.1007/978-3-319-48054-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-48054-1.jpg', NULL, NULL, NULL),
(5995, 'Joseph G. McCarthy', '', '978-3-319-52564-8', 10850, 0, '2017', 'This book, edited by a leading pioneer of craniofacial distraction, summarizes the progress achieved in the field in a way that will serve the needs of the practicing clinician.  All components of the craniofacial anatomy are covered and all topics are discussed in depth: clinical and anatomic pathology, diagnostic studies, treatment protocols, preoperative planning (including the latest virtual programs), device selection, operating room technical considerations, postoperative management, and intermediate/long-term follow-up. Relevant and timely studies from the literature are cited. The book is excellently illustrated, with many patient photos, radiographs, and drawings. Craniofacial Distraction will be a superb, up-to-date resource for a wide range of practitioners, including maxillofacial surgeons, craniofacial surgeons, plastic surgeons, head and neck surgeons, pediatric surgeons, orthodontists, prosthodontists, and pedodontists.', 'Craniofacial Distraction', 'http://link.springer.com/book/10.1007/978-3-319-52564-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-52564-8.jpg', 'Springer International Publishing', NULL, NULL),
(5996, 'Prof. Moni Abraham Kuriakose', '', '978-3-319-43857-3', 9770, 0, '2017', 'This is the last of four volumes that together offer an authoritative, in-depth reference guide covering all aspects of the management of oral cancer from a multidisciplinary perspective and on the basis of a strong scientific foundation. This volume focuses on the topic of comprehensive rehabilitation and supportive care in oral cancer. The coverage includes the role of maxillofacial prosthodontics, advances in anaplastology techniques, and management of oral mucositis during radiation and chemotherapy. Holistic and supportive care approaches are discussed, and advice is provided on post-therapy surveillance and the use of different measures to assess quality of life. Nutritional evaluation and management and issues relating to healthcare economics are also considered. This volume will be of interest both to practicing specialists and to ancillary service staff involved in the care of oral cancer patients.\nOverview on all volumes:\nVolume 1: Biology, Epidemiology, Etiology, and Prevention\nVolume 2: Diagnosis and Management\nVolume 3: Oral and Maxillofacial Reconstructive Surgery\n\nVolume 4: Rehabilitation and Supportive Care', 'Contemporary Oral Oncology', 'http://link.springer.com/book/10.1007/978-3-319-43857-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-43857-3.jpg', 'Springer', NULL, NULL),
(5997, 'Prof. Moni Abraham Kuriakose', '', '978-3-319-14917-2', 9230, 0, '2017', 'This is the second of four volumes that together offer an authoritative, in-depth reference guide covering all aspects of the management of oral cancer from a multidisciplinary perspective and on the basis of a strong scientific foundation. This volume addresses a range of management issues in oral cancer, from imaging and staging through to the roles of radiation therapy and chemotherapy. Principles of ablative surgery are explained, and neck dissection and sentinel lymph node biopsy techniques, described. Detailed consideration is also given to the management of complications, salvage surgery and re-radiation, the biologic basis of treatment failure, and emerging approaches to overcome treatment resistance. The inclusion of resource-stratified guidelines will meet the needs of practitioners in different geographic regions with varying resources.\nOverview on all volumes:\n\nVolume 2: Diagnosis and Management\nVolume 3: Oral and Maxillofacial Reconstructive Surgery', 'Contemporary Oral Oncology', 'http://link.springer.com/book/10.1007/978-3-319-14917-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-14917-2.jpg', 'Springer London, Limited', NULL, NULL);
INSERT INTO `book` (`id`, `author`, `edition`, `isbn`, `price`, `quantity`, `year`, `description`, `book_title`, `url`, `cover_image`, `publisher`, `status`, `created_at`) VALUES
(5998, 'Prof. Moni Abraham Kuriakose', '', '978-3-319-43854-2', 9230, 0, '2017', 'This is the third of four volumes that together offer an authoritative, in-depth reference guide covering all aspects of the management of oral cancer from a multidisciplinary perspective and on the basis of a strong scientific foundation. This volume is devoted to the reconstructive surgical techniques used in patients with oral cancer. Following introductory chapters outlining the general principles of reconstructive surgery in the oral cavity and the planning of maxillofacial reconstruction, detailed descriptions of the options and techniques employed in reconstruction of each of the functional subunits are provided. Important technologic advances are also discussed, including image-guided surgery, robotic surgery, and tissue-engineered and prefabricated approaches. Finally, the current status of facial transplantation for maxillofacial reconstruction is reviewed. This volume is intended for both trainees and practicing surgeons.\nOve\n\nVolume 1: Biology, Epidemiology, Etiology, and Prevention\n\n\nVolume 3: Oral and Maxillofacial Reconstructive Surgery\n\n\nVolume 4: Rehabilitation and Supportive Care', 'Contemporary Oral Oncology', 'http://link.springer.com/book/10.1007/978-3-319-43854-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-43854-2.jpg', NULL, NULL, NULL),
(5999, 'Pieter J. Slootweg', '', '978-3-319-28085-1', 28100, 0, '2016', 'This book covers the complete field of oral and maxillofacial pathology – from Addisons disease to Zimmerman-Laband syndrome. The alphabetically arranged entries, each of which provides a detailed description of a specific pathological disease pattern, allow readers to quickly and easily find \nthe information they need.', 'Dental and Oral Pathology', 'http://link.springer.com/referencework/10.1007/978-3-319-28085-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-28085-1.jpg', NULL, NULL, NULL),
(6000, 'Louis G. Mercuri', '', '978-3-319-21389-7', 17360, 0, '2016', 'This is the first text that deals specifically with TMJ TJR. Each chapter is authored by either a basic science researcher or clinician known for their interest and expertise in this field. The text provides the reader with state-of-the-art analysis of all aspects of total temporomandibular joint replacement (TMJ TJR), starting with cutting-edge evidence on the biomechanics of the TMJ. The intriguing history of TMJ TJR is presented to provide an understanding of why some prior TMJ TJR devices failed and how what was learned from those failures has led to the improvements exhibited in present TMJ TJR devices.   Expert chapters discuss both stock and custom designs, their indications and contraindications, primary operative techniques, combined TMJ TJR and orthognathic surgical techniques, and the devices\' adaption for use as segmental or total mandibular replacement devices after ablative surgery. Clinical outcomes and avoidance as well as management of complications are detailed.  Numerous helpful illustrations and radiographs are presented to assist readers in understanding and carrying out the described procedures. Important evidence from both the orthopedic and TMJ TJR literature relating to material sensitivity and mechanical wear will be reported. Finally, the role bioengineered tissue may hold for the future of TMJ TJR will be discussed.', 'Temporomandibular Joint Total Joint Replacement â€“ TMJ TJR', 'http://link.springer.com/book/10.1007/978-3-319-21389-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-21389-7.jpg', 'Springer', NULL, NULL),
(6001, 'Tadaaki KiritaKen Omura', '', '978-4-431-54938-3', 13020, 0, '2015', 'Oral cancer is frequently diagnosed late, when the disease has advanced with lesions that are large and deeply invasive and with metastasis to regional lymph nodes, leading to increased mortality. Moreover, late diagnosis and treatment often result in considerable morbidity of oral and maxillofacial structures and poor appearance and function following therapy. This book provides head and neck oncologists, oral oncologists, oral and maxillofacial surgeons, medical oncologists, dentists and other members of dental teams furnishing supportive care with a systematic review of recent diagnostic and therapeutic advances in oral cancer. The various authoritative chapters are prepared by specialists who are active leaders in each basic and clinical field. All chapters address individual and collective issues that arise in managing oral cancer patients with difficult treatment problems and provide insight into the multiple valid management approaches available. The authors offer an extensive source of information about oral cancers and encourage the clinician to be flexible and innovative, giving physicians and medical personnel the background information to make the best, educated, responsible decisions for individual patients.', 'Oral Cancer', 'http://link.springer.com/book/10.1007/978-4-431-54938-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-4-431-54938-3.jpg', 'Springer London, Limited', NULL, NULL),
(6002, 'Nejat ErverdiMelih Motro', '', '978-3-319-07707-9', 9770, 0, '2015', 'This book describes a new method of alveolar distraction osteogenesis that offers important advantages and can be used for the treatment of various orthopedic abnormalities and congenital malformations. Detailed guidance is provided on selection of patients suitable for alveolar distraction, including those with cleft lip and palate, skeletal class II malocclusions and cystic lesions involving the alveolus. All aspects of treatment using the ArchWise distraction appliance are then covered, including technical preparation, surgical set-up and osteotomies, docking site surgery, orthodontic finishing, implant placement and prosthetic restorations. Relevant information is also included on the principles of distraction osteogenesis and bone histology and quality after the procedure. The book concludes with helpful case presentations covering different scenarios in which ArchWise distraction of alveolar bone is appropriate.', 'Alveolar Distraction Osteogenesis', 'http://link.springer.com/book/10.1007/978-3-319-07707-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-07707-9.jpg', 'Springer', NULL, NULL),
(6003, 'Sajeesh Kumar', '', '978-3-319-08973-7', 9770, 0, '2015', 'Teledentistry is of growing interest to the healthcare world. Over the last few years, momentum is growing in research and service in Teledentistry - mostly carried out by tertiary medical institutes across the world. While Teledentistry is advanced in some sub-specialties, it has high potential to receive more attention from general communities, dentists, dental hygienists, physicians, nurses, researchers and students. For the first time, this book will present essential knowledge from experts in this field. They will discuss the current status of technology and service in various Telledentistry sub specialties and its future implications. Written by experts from around the globe, (i.e., from USA, Europe, Australia and Asia), this book presents technical issues and clinical applications. It includes collective experiences from dental service providers in different parts of the world practicing a wide range of Teledentistry applications. This book lays the foundations for the globalization of Teledentistry procedures, making it possible for dental service to be delivered anywhere in the world.', 'Teledentistry', 'http://link.springer.com/book/10.1007/978-3-319-08973-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-08973-7.jpg', 'Springer', NULL, NULL),
(6004, 'Carlos Navarro Vila', '', '978-3-319-20487-1', 9770, 0, '2015', 'This book describes the reconstructive procedures currently used by the authors for the treatment of oral and maxillofacial defects, based on twenty-five years of experience at a major European University Hospital. The coverage encompasses mandibular, maxillary, orbitocranial, intraoral soft tissue and cutaneous defect reconstruction. Controversies in defect reconstruction are discussed, and clear guidance is given on the optimal choice of reconstructive technique according to the location and size of the defect. Full descriptions are provided of both aesthetic and functional procedures, with use of implants and dental prostheses. The resultant functional and aesthetic reconstruction will enable the patient quickly to resume a normal social, family and professional life. All of the chapters include representative images depicting each stage of treatment, from preoperative study, through intraoperative and postoperative appearances, to ultimate outcome upon rehabilitation.', 'Reconstructive Oral and Maxillofacial Surgery', 'http://link.springer.com/book/10.1007/978-3-319-20487-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-20487-1.jpg', 'Springer', NULL, NULL),
(6005, 'Sven Otto', '', '978-3-662-43733-9', 9770, 0, '2015', 'Osteonecrosis of the jaws is a well-known side-effect of antiresorptive therapy that predominantly occurs in patients suffering from malignant diseases and receiving intravenous administrations of nitrogen-containing bisphosphonates or subcutaneous administrations of denosumab, a monoclonal antibody. Less frequently it may also be observed in patients with osteoporosis who are being treated with these antiresorptive drugs \nThis textbook provides detailed, up-to-date information on all aspects of medication-related osteonecrosis of the jaws, including clinical features, pathogenesis, treatment options, and preventive measures. It also explains safe prevention and treatment strategies for patients receiving antiresorptive drugs who require extractions, implant insertions, and other dento-alveolar surgeries. This book will be of major interest for medical and dental students, dentists, and oral and maxillofacial surgeons as well as osteologists and oncologists.', 'Medication-Related Osteonecrosis of the Jaws', 'http://link.springer.com/book/10.1007/978-3-662-43733-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-43733-9.jpg', 'Springer', NULL, NULL),
(6006, 'Sanjay Patole', '', '978-3-319-11526-9', 9230, 0, '2015', 'This book will provide anyone with an interest in the clinic with a basic guide on those things that are not taught during medical school or any other pre-clinical trainings. The line-up of authors was carefully assembled to include experts in all respective fields to give this volume the authority it requires to be a relevant text for many.', 'Management and Leadership â€“ A Guide for Clinical Professionals', 'http://link.springer.com/book/10.1007/978-3-319-11526-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-11526-9.jpg', 'Springer', NULL, NULL),
(6007, 'Riva Touger-DeckerConnie MobleyJoel B. Epstein', '', '978-1-60761-490-6', 17360, 0, '2014', 'This second edition addresses the complex, multifaceted relationships between nutrition and oral health, explores proposed relationships between oral, systemic and nutritional well-being and provides insights into interprofessional, comprehensive care for individuals. Chapters focus on diet, nutrition and oral health promotion and disease prevention across the lifespan, oral and dental diseases and disorders, oral manifestations of systemic diseases, and discussions of the synergy between oral tissues and nutrients. Cutting edge research issues regarding the relationship of individual antioxidants, trace elements, polyphenols and other nutrient substrates and oral health/disease, nutrigenomics, screening for nutrition and oral risk and other areas are covered in detail. Editors and authors include experts in nutrition and oral health from around the world. This second edition is a invaluable resource for  health professionals in the fields of nutrition and dentistry as well as other disciplines whose research, practice and education includes nutrition and oral medicine. It is an excellent resource for graduate level nutrition and dental students, dental and nutrition practitioners, educators and researchers as well as other health professionals.', 'Nutrition and Oral Medicine', 'http://link.springer.com/book/10.1007/978-1-60761-490-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-60761-490-6.jpg', 'Humana Press', NULL, NULL),
(6008, 'Henrik HellquistAlena Skalova', '', '978-3-540-46915-5', 11940, 0, '2014', 'Over the last 25 years it has become more and more evident that salivary gland pathology is by far the subject within head and neck pathology that causes most diagnostic challenges and problems for general pathologists. During courses the author has given, consultants and trainees alike have expressed the lack of a comprehensive, useful book on salivary gland pathology. Such a book needs to be broad and to illustrate almost every variant of all tumor entities. Another important feature to incorporate is the newly gained knowledge about genetics in salivary gland tumors, a knowledge that has emerged during the last 3-4 years only (and is growing continuously). A mapping of the immunophenotypes of salivary gland tumors is neither available today and will greatly benefit in routine diagnostic work.', 'Histopathology of the Salivary Glands', 'http://link.springer.com/book/10.1007/978-3-540-46915-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-540-46915-5.jpg', 'Springer London, Limited', NULL, NULL),
(6009, 'Pietro CarusoEnzo SilvestriLuca Maria Sconfienza', '', '978-88-470-5319-9', 10850, 0, '2014', 'Cone beam computed tomography (CBCT) has become the standard of reference in dental imaging. The distribution of CBCT devices is increasingly wide, and the number of required examinations is constantly growing. In this setting, it is now essential that medical and technical staff receive specific training in the use of CBCT and that technical guidelines for CBCT examinations are established. This clearly structured book on CBCT will be an ideal aid in daily clinical practice. It clearly explains basic CBCT anatomy, examination technique, and the use of 3D reformatting software. A wide range of cases are presented, covering the most frequent and relevant conditions and pathologies, including dental anomalies, inflammatory and degenerative disease, tumors, and implants.', 'Cone Beam CT and 3D imaging', 'http://link.springer.com/book/10.1007/978-88-470-5319-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-88-470-5319-9.jpg', 'Springer London, Limited', NULL, NULL),
(6010, 'Kameshwar Prasad', '', '978-81-322-0831-0', 6190, 0, '2014', 'This is a basic book on evidence-based medicine (EBM). It starts with an introduction to the topic. It outlines the relationship between EBM and research and quality of care. Then It goes on to cover the most commonly used modules of EBM, i.e. therapy, diagnosis, prognosis and meta-analysis. Each module starts with an introduction to fundamental concepts, and description of the related research process, and then follows the critical appraisal of related type of research artcle. At the end, it covers the different systems of grading of level of evidence and strength of recommendations. The book also has three examples of critical appraisal on diagnosis, therapy, and meta-analysis.', 'Fundamentals of Evidence Based Medicine', 'http://link.springer.com/book/10.1007/978-81-322-0831-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-81-322-0831-0.jpg', 'Springer London, Limited', NULL, NULL),
(6011, 'Nalini VadiveluAmarender VadiveluAlan David Kaye', '', '978-3-319-01875-1', 5430, 0, '2014', 'Because diagnosing orofacial pain can be a challenge, the book describes the appropriate history-taking methods, detailed examinations, and relevant tests that will help clinicians to work through the differential diagnosis. Effective medical, surgical, and behavioral approaches are presented, and the importance of a multimodal approach is consistently emphasized throughout the book. The target audience includes pain physicians, anesthesiologists, dentists, neurologists, nurse practitioners, and physician’s assistants.', 'Orofacial Pain', 'http://link.springer.com/book/10.1007/978-3-319-01875-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-319-01875-1.jpg', 'Springer', NULL, NULL),
(6012, 'Samuel Berkowitz', '', '978-3-642-30770-6', 24850, 0, '2013', 'Cleft Lip and Palate: Diagnosis and Management is an unparalleled review of treatment concepts in all areas of cleft involvement presented by an international team of experienced clinicians. A unique feature of the book is that it largely consists of longitudinal facial and palatal growth studies of dental casts, photographs, panorexes, and cephalographs from birth to adolescence. Throughout the discussion of growth and treatment concepts, the importance of differential diagnosis in treatment planning is underscored. The underlying argument is that all the treatment goals – good speech, facial aesthetics, dental occlusion, and psychological development – may be realized without the need to sacrifice one for another. This updated third edition includes new chapters on further successful physiological treatment protocols, strategies for coping with psychological effects, the excellent clinical work being undertaken in Asia, future multicenter palatal growth studies, and other topics.', 'Cleft Lip and Palate', 'http://link.springer.com/book/10.1007/978-3-642-30770-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-30770-6.jpg', 'Springer London, Limited', NULL, NULL),
(6013, 'Michael Miloro', '', '978-3-642-35539-4', 18450, 0, '2013', 'Trigeminal nerve injuries present complex clinical challenges and can be very distressing for patients, resulting in abnormal sensations of the oro-facial region, yet surgeons may lack the knowledge required for optimal patient management based upon the specific nerve injury. This textbook is the first to be devoted to the diagnosis and management of trigeminal nerve injuries. A wide range of topics are covered, including historical perspectives, demographics, etiology, anatomy and physiology, pathophysiology, clinical neurosensory testing, nonsurgical management, and surgical management and principles of microneurosurgery, specifically involving the inferior alveolar and lingual nerves. Algorithms and a glossary are provided that will assist in the clinical management of these complex scenarios. The authors include surgeons with considerable experience and expertise in the field who have previously published on the subject. This book will serve as an ideal clinical reference for surgeons with patients who sustain trigeminal nerve injuries.', 'Trigeminal Nerve Injuries', 'http://link.springer.com/book/10.1007/978-3-642-35539-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-35539-4.jpg', 'Springer London, Limited', NULL, NULL),
(6014, 'Pieter J. Slootweg', '', '978-3-642-36714-4', 9230, 0, '2013', 'This new, updated edition of Dental Pathology will assist in the recognition and diagnosis of gross dental abnormalities. Topics covered include disturbances in tooth formation, acquired dental diseases, including caries and its sequelae, periodontal disease, and odontogenic tumours. Practically applicable knowledge is provided on the histology and histopathology of the changes that are seen in diseases of the dental and periodontal tissues, and attention is also paid to the histological alterations induced by dental treatment. Compared with the first edition, ca. 50% more illustrations are included and more information is provided on diagnostically difficult cases. This work will be an invaluable companion for dental practitioners who need to make diagnoses in such cases and will also be of value for surgical pathologists, clinical geneticists, and oral and maxillofacial surgeons.', 'Dental Pathology', 'http://link.springer.com/book/10.1007/978-3-642-36714-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-36714-4.jpg', 'Springer London, Limited', NULL, NULL),
(6015, 'Ignazio PandolfoSilvio Mazziotti', '', '978-88-470-5289-5', 5430, 0, '2013', 'Although orthopantomography (OPT) is a very frequently employed radiological examination, even the expert radiologist can encounter difficulty in reporting the findings owing to the specific terminology, the nature of the diagnostic queries, and the need to describe precisely the clinical implications for the dentist. Additionally, artifacts are a frequent occurrence, and many radiologists and dentists are unfamiliar with their causes and solutions. Methodological inaccuracies during the execution of OPTs also have important clinical implications. For all of these reasons, this richly illustrated monograph on OPT sets out to describe in detail diverse technical and methodological aspects of the examination, from image acquisition through to artifact generation due to lack of experience or malfunctioning. Possible solutions are suggested for all of the most common diagnostic and methodological problems. Emphasis is placed on appropriate terminology and guidance offered on the interpretation of findings in a range of conditions, including the most common odontological problems. This book will be of great value to the radiologist in routine interpretation and reporting of OPTs.', 'Orthopantomography', 'http://link.springer.com/book/10.1007/978-88-470-5289-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-88-470-5289-5.jpg', 'Springer', NULL, NULL),
(6016, 'Francesco Chiappelli', '', '978-3-642-23144-5', 17360, 0, '2012', 'Recent trends in health care across the United States and internationally have emphasized a novel approach that consists in comparing the effectiveness and efficacy of treatment interventions with a patient-centered emphasis (i.e., evidence-based health care), while ensuring cost constraints, maximizing benefits, and minimizing risks. In this book, experts in comparative effectiveness and efficacy research and analysis for practice (CEERAP) in health care in general address a range of topical issues. The emphasis is on implications for endodontics and nursing, both of which are considered in a series of detailed chapters. Commonalities and differences among CEERAP, utility-based and logic-based analysis and decision-making, and evidence-based and patient-centered practice are defined and discussed. The book concludes by examining applications for CEERAP in developing patient-centered optimal treatment interventions for the next decade.', 'Comparative Effectiveness and Efficacy Research and Analysis for Practice (CEERAP)', 'http://link.springer.com/book/10.1007/978-3-642-23144-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-23144-5.jpg', 'Springer Berlin Heidelberg', NULL, NULL),
(6017, 'Keyvan Nouri', '', '978-0-85729-281-0', 10850, 0, '2012', 'Laser technology is constantly evolving and progressing. The use of laser therapy is vastly expanding and for this reason a medical book of this magnitude is necessary. Lasers and Light Therapy includes an up-to-date comprehensive look at lasers and light therapy not only in the field of Cutaneous Laser Surgery, but in other medical specialties as well.', 'Lasers in Dermatology and Medicine', 'http://link.springer.com/book/10.1007/978-0-85729-281-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-0-85729-281-0.jpg', 'Springer-Verlag London Limited', NULL, NULL),
(6018, 'Fabio MeneghiniPaolo Biondi', '', '978-3-642-27228-8', 10850, 0, '2012', 'This richly illustrated book presents a straightforward non-instrumental method of clinical facial analysis in preparation for aesthetic surgery, orthognathic surgery, and orthodontic treatments. After discussion of various practical aspects of facial examination and photography, analysis of different regions of the face and dentofacial deformities is discussed in a series of detailed chapters. At the end of each of these chapters, multiple-choice checklists are included that will help the reader to perform step-by-step regional analysis. Important features of the book are its multidisciplinary approach and the emphasis placed on the relationship between different parts of the face. This second edition has been thoroughly updated and includes a new chapter on recording and documentation relating specifically to aesthetic facial surgery.', 'Clinical Facial Analysis', 'http://link.springer.com/book/10.1007/978-3-642-27228-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-27228-8.jpg', 'Springer', NULL, NULL),
(6019, 'Francesco Saverio De Ponte', '', '978-88-470-2083-2', 9770, 0, '2012', 'During the early 19th century, it was discovered that adding yellow (now called white) phosphorous to matchstick heads made it easier to ignite matches. The phosphorous vapors were breathed in by workers and combined with other chemicals in the body to produce a potent nitrogen-containing bisphosphonate. Today\'s oral nitrogen-containing bisphosphonates and intravenous nitrogen-containing bisphosphonates circulate around the body the same way as the phosphorous vapors, and are absorbed into bone and ingested by osteoclasts. When this unique binding process of bisphosphonates to bone occurs, osteoclasts are poisoned, and this reduces or eliminates bone turnover. Alveolar bone in the mandible and maxilla turns over more rapidly than in long bones, so the jaws are a better target for bisphosphonate toxicity. It wasn\'t until 2003 that today\'s intravenous and oral nitrogen-containing bisphosphonate medications were implicated as major risk factors in the development of exposed necrotic boneof the jaws. Most of the researchers who reported cases of bisphosphonate-induced osteonecrosis of the jaw found that these patients were treated with zoledronate, pamidronate, or a combination of these drugs, which are commonly used for treating breast cancer or myeloma. In about 5% of cases, subjects with BIONJ were being treated for osteoporosis. Precipitating events that contribute to BIONJ are tooth extractions (about 50% of cases), mandibular exostoses, periodontal disease, and local trauma from ill-fitting dentures. It is not known if the placement of dental implants is a precipitating factor. The book aims to meet the need of medical practitioners working in all fields that use bisphosphonates, and to present the conservative and surgical treatment methods currently in use. There will also be detailed information on the literature relating to dental implants in patients treated with bisphosphonates.', 'Bisphosphonates and Osteonecrosis of the Jaw: A Multidisciplinary Approach', 'http://link.springer.com/book/10.1007/978-88-470-2083-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-88-470-2083-2.jpg', 'Springer', NULL, NULL),
(6020, 'Velio Bocci', '', '978-90-481-9234-2', 23760, 0, '2011', 'Oxygen-Ozone therapy is a complementary approach less known than homeopathy and acupuncture because it has come of age only three decades ago. This book clarifies that, in the often nebulous field of natural medicine, the biological bases of ozone therapy are totally in line with classical biochemistry, physiological and pharmacological knowledge. Ozone is an oxidizing molecule, a sort of super active oxygen, which, by reacting with blood components generates a number of chemical messengers responsible for activating crucial biological functions such as oxygen delivery, immune activation, release of hormones and induction of antioxidant enzymes, which is an exceptional property for correcting the chronic oxidative stress present in atherosclerosis, diabetes and cancer. Moreover, by inducing nitric oxide synthase, ozone therapy may mobilize endogenous stem cells, which will promote regeneration of ischemic tissues. The description of these phenomena offers the first comprehensive picture for understanding how ozone works and why. When properly used as a real drug within therapeutic range, ozone therapy does not only does not procure adverse effects but yields a feeling of wellness. Half the book describes the value of ozone treatment in several diseases, particularly cutanious infection and vascular diseases where ozone really behaves as a “wonder drug”. The book has been written for clinical researchers, physicians and ozone therapists, but also for the layman or the patient interested in this therapy.', 'OZONE', 'http://link.springer.com/book/10.1007/978-90-481-9234-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-90-481-9234-2.jpg', 'Springer', NULL, NULL),
(6021, 'Karl HÃ¶rmannThomas Verse', '', '978-3-540-77786-1', 10850, 0, '2010', 'Nasal continuous positive airway pressure ventilation is the gold standard in the treatment of obstructive sleep apnea. Long-term compliance rates are about 60%. Therefore, several alternative treatment options are of special interest. Beside conservative therapies, various surgical concepts exist. The field of surgery for sleep disordered breathing has rapidly grown with new instrumentation and surgical techniques in the last 10 years. Surgeons in these fields have to attend scientific meetings, participate in workshops, and read the literature to stay up to date. In our sleep laboratories we conduct 30 polysomnographies each night. Each year, we perform almost 1,000 surgical procedures for sleep disordered breathing apart from numerous other conservative and apparative treatment modalities. Referring to our expe- ence and the present literature, we tried to give new information on surgical techniques in this second edition. The chapters are grouped in different anatomical fields of interest. We wanted to give general advice and specific new hints for the surgery of sleep disordered breathing so that the reader learns basic techniques followed by more advanced surgery. In addition to the illustrated surgical descriptions, the chapters contain informations about indications and contraindications of each surgical procedure and the postoperative care. Special interest has been dedicated to evidence-based medicine. So in each chapter, there is a table of references summarizing the effectiveness of the procedure and EBM grade.', 'Surgery for Sleep Disordered Breathing', 'http://link.springer.com/book/10.1007/978-3-540-77786-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-540-77786-1.jpg', 'Springer', NULL, NULL),
(6022, 'Francesco Chiappelli', '', '978-3-642-05025-1', 7600, 0, '2010', 'Health care is witnessing an explosion of fundamental, clinical and translational research evidence. The emerging paradigm of evidence-based health care rests on the judicious integration of the patient needs/wants, the provider\'s expertise, and the best available research evidence in the treatment plan. The purpose of this book is to discuss the promise and the limitations of incorporating the best available evidence in clinical practice. It seeks to characterize and define how best available research evidence can be used in clinical practice and to what respect it applies to current public health issues.', 'Evidence-Based Practice: Toward Optimizing Clinical Outcomes', 'http://link.springer.com/book/10.1007/978-3-642-05025-1', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-05025-1.jpg', 'Springer-Verlag Berlin Heidelberg', NULL, NULL),
(6023, 'Ira B. LamsterMary E. Northridge', '', '978-0-387-74337-0', 11940, 0, '2008', 'Improving Oral Health for the Elderly: An Interdisciplinary Approach\n\nEdited by Ira B. Lamster, Columbia University College of Dental Medicine, New York\nMary E. Northridge, Mailman School of Public Health, Columbia University, New York\n\nImproving Oral Health for the Elderly: An Interdisciplinary Approach examines in depth a crucial yet frequently overlooked indicator of seniors’ quality of life. By combining a lifespan approach to health with a biopsychosocial perspective on health disparities, this book places oral health in the larger context of physical and mental well-being. Chapter authors emphasize elders’ distinct needs as a group, the interplay of factors contributing to the oral disease burden (from increased tooth retention to the absence of dental benefits as part of Medicare), and the necessity—and overall benefits—of improved service delivery and interdisciplinary care. The result is an invaluable set of recommendations to the clinical, research, and administrative communities that they can use to better understand and serve this steadily growing population.\n\nAmong the topics covered:\n\n\n\nImproving Oral Health for the Elderly: An Interdisciplinary Approach is of immediate interest to readers in dentistry, medicine, and aging studies, but this unique volume also merits the attention of professionals and researchers involved in community and public health, healthpromotion, disease prevention, social work, health care policy and planning.', 'Improving Oral Health for the Elderly', 'http://link.springer.com/book/10.1007/978-0-387-74337-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-0-387-74337-0.jpg', 'Springer', NULL, NULL),
(6024, 'Allan G. Farman', '', '978-3-540-46230-9', 10850, 0, '2007', 'Panoramic radiology systems are currently being used in more practices than at other any time in the past. The practitioner now has decisions to make regarding detector technology selection for image acquisition and must remain informed about appropriate usage. This book is applicable to all panoramic dental images and equipment. It approaches panoramic radiology usage in the context of general and specialty applications.', 'Panoramic Radiology', 'http://link.springer.com/book/10.1007/978-3-540-46230-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-540-46230-9.jpg', 'Springer London, Limited', NULL, NULL),
(6025, 'Pieter J. Slootweg MD, DMD, PhD', '', '978-3-540-71691-4', 9770, 0, '2007', NULL, 'Dental Pathology', 'http://link.springer.com/book/10.1007/978-3-540-71691-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-540-71691-4.jpg', 'Springer', NULL, NULL),
(6026, 'Samuel Berkowitz DDS, MS, FICD', '', '978-3-540-30020-5', 56310, 0, '2006', NULL, 'Cleft Lip and Palate', 'http://link.springer.com/book/10.1007/3-540-30020-1', 'https://media.springernature.com/w153/springer-static/cover/book/3-540-30020-1.jpg', 'Springer London, Limited', NULL, NULL),
(6027, 'Gwen R.J. Swennen MD,DMD,PhDFilip Schutyser MScJarg-Erich Hausamen MD,DMD,PhD', '', '978-3-540-29011-7', 17360, 0, '2006', NULL, 'Three-Dimensional Cephalometry', 'http://link.springer.com/book/10.1007/3-540-29011-7', 'https://media.springernature.com/w153/springer-static/cover/book/3-540-29011-7.jpg', 'Springer London, Limited', NULL, NULL),
(6028, 'Ulrich MeyerHans Peter Wiesmann', '', '978-3-540-33606-8', 15190, 0, '2006', 'Bone and Cartilage Engineering provides a complete overview of recent knowledge in bone and cartilage tissue engineering. It follows a logical approach to the various aspects of extracorporal bone and cartilage tissue engineering. The cooperation between a basic scientist and a clinician made it possible to structure the book\'s content and style according to the interdisciplinary character of the field. The comprehensive nature of the book, including detailed descriptions of laboratory procedures, preclinical approaches, clinical applications, and regulatory issues, will make it an invaluable basis for everyone working in this field. This book will serve as a fundamental tool for basic researchers to establish or refine tissue engineering techniques as well as for clinicians to understand and use this modern therapeutic option.', 'Bone and Cartilage Engineering', 'http://link.springer.com/book/10.1007/3-540-33606-0', 'https://media.springernature.com/w153/springer-static/cover/book/3-540-33606-0.jpg', 'Springer', NULL, NULL),
(6029, 'Prof.Dr. med. Rudolf F. GuthoffChristophe Baudouin MD, PhdProf.Dr. rer. nat. Joachim Stave', '', '978-3-540-32707-3', 11940, 0, '2006', 'Confocal microscopy with laser scanning technology yields in-vivo images of ocular and ocular adnexal surfaces that are so brilliant that they rival histology in terms of quality.This unique atlas and textbook demonstrates normal in-vivo anatomy of the cornea, limbus and conjunctiva, quantifies various cellular structures using cell-density calculations and establishes correlations between novel optical sections of various diseases of the ocular surface and clinical findings. Furthermore, it supports the interpretation of novel high-magnification optical sections by comparing corneal and conjunctival imprint cytology with in-vivo images and describes early inflammatory changes in corneal grafts, as well as corneal conjunctivalisation in limbal stem cell deficiency, corneal dystrophies or infections, flap interface and margin characteristics after laser in-situ keratomileusis (LASIK). In addition, it instructs the reader about diagnostic and therapeutic follow-up strategies and provides a brief introduction to applications in other fields such as dentistry and ear, nose and throat surgery.', 'Atlas of Confocal Laser Scanning In-vivo Microscopy in Ophthalmology', 'http://link.springer.com/book/10.1007/3-540-32707-X', 'https://media.springernature.com/w153/springer-static/cover/book/3-540-32707-X.jpg', 'Springer', NULL, NULL),
(6030, 'Prof. Dr. Karl HÃ¶rmann M.D.Dr. Thomas Verse M.D.', '', '978-3-540-27608-1', 15190, 0, '2005', 'In recent years, the spectrum of therapy for sleep-related breathing disorders has been immensely enriched by numerous innovative surgical procedures and techniques. Deciding which therapy is most appropriate for which patient is often a difficult matter, especially in light of the non-surgical alternatives. This book analyses the efficiency of the recognised surgical procedures; it is rooted in evidence-based medicine. Indications, techniques, complications, and specific follow-up treatments in the realm of sleep medicine have been compiled in the form of a primer. The authors are directors of one of the largest otolaryngological sleep laboratories in the world and perform approximately 1,500 surgical sleep medicine procedures per year. The complete surgical and sleep medicine know-how of the authors, as well as the experience of numerous international courses on sleep surgery, have been incorporated into this volume. It is therefore the fundamental textbook for sleep medicine surgeons.', 'Surgery for Sleep-Disordered Breathing', 'http://link.springer.com/book/10.1007/3-540-27608-4', 'https://media.springernature.com/w153/springer-static/cover/book/3-540-27608-4.jpg', 'Springer London, Limited', NULL, NULL),
(6031, 'Prof. Dr. Mosaad Megahed', '', '978-3-642-18651-6', 9770, 0, '2004', NULL, 'Histopathology of Blistering Diseases', 'http://link.springer.com/book/10.1007/978-3-642-18651-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-18651-6.jpg', 'Springer London, Limited', NULL, NULL),
(6032, 'Hugo L. Obwegeser M.D., D.M.D., F.D.S.R.C.S. (Eng.), Hon. F.D.S.R.C.P.S. (Glas.); Hon. F.F.D.R.C.S. (Ire.)', '', '978-3-662-04534-3', 22680, 0, '2001', 'Was ever a foreword requested for God\'s words? It is not indecent to write a preface for Hugo\'s \"Growing Mandible\"? After training in the Jaw\'s Old Testament, Hugo is writing the New One that he taught for 40 years long. Indeed, the last decade has been fertile in mechanical gadgets which have made diagnosis and surgery easier, such as, accurate CT 3-D images, and absorbable plating or osteodistraction, which brings a fine touch to treatment timing in children. However, all of this does not encompass the intellectual process, basic principles, tactics and procedures.', 'Mandibular Growth Anomalies', 'http://link.springer.com/book/10.1007/978-3-662-04534-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-04534-3.jpg', 'Springer London, Limited', NULL, NULL),
(6033, 'Ph. D. L. Yahia', '', '978-3-642-59768-8', 9770, 0, '2000', 'Shape memory alloy implants or \"smart biomaterial\" have already been used in humans for 20 years in selected countries. Restrictions in the use of biomaterials in living organisms being reduced throughout the world now the use of SMA implants continue to expand in the fields of vascular and orthopaedic surgery, minimally invasive surgery and drug delivery systems. This book is to provide a state of the art of SMA implants and devices. For the first time long-term clinical experiences and techniques of SMA biocompatibility are presented.', 'Shape Memory Implants', 'http://link.springer.com/book/10.1007/978-3-642-59768-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-59768-8.jpg', 'Springer London, Limited', NULL, NULL),
(6034, 'Prof. Torello M. Lotti M.D.Lawrence Charles Parish M.D., F.A.C.PRoy Steele Rogers III M.D.', '', '978-3-642-59821-0', 9770, 0, '1999', 'Oral Medicine contains a brillant collection of colour pictures, augmented by appropriate discussion. Both common and unusual afflictions of the oral cavity are described. Sections on clinical manifestations, histologic findings, differential diagnosis, and treatment, complemented by significant references, have been written by selected authorities in the field. Dermatologists, dentists, and even primary care physicians will find this volume to be indispensable in their practices.', 'Oral Diseases', 'http://link.springer.com/book/10.1007/978-3-642-59821-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-59821-0.jpg', 'Springer London, Limited', NULL, NULL),
(6035, 'Jonathan BlackGarth Hastings', '', '978-1-4615-5801-9', 9770, 0, '1998', 'Progress in the development of surgical implant materials has been hindered by the lack of basic information on the nature of the tissues, organs and systems being repaired or replaced. Materials\' properties of living systems, whose study has been conducted largely under the rubric of tissue mechanics, has tended to be more descriptive than quantitative. In the early days of the modern surgical implant era, this deficiency was not critical. However, as implants continue to improve and both longer service life and higher reliability are sought, the inability to predict the behavior of implanted manufactured materials has revealed the relative lack of knowledge of the materials properties of the supporting or host system, either in health or disease. Such a situation is unacceptable in more conventional engineering practice: the success of new designs for aeronautical and marine applications depends exquisitely upon a detailed, disciplined and quantitative knowledge of service environments, including the properties of materials which will be encountered and interacted with. Thus the knowledge of the myriad physical properties of ocean ice makes possible the design and development of icebreakers without the need for trial and error. In contrast, the development period for a new surgical implant, incorporating new materials, may well exceed a decade and even then only short term performance predictions can be made.', 'Handbook of Biomaterial Properties', 'http://link.springer.com/book/10.1007/978-1-4615-5801-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4615-5801-9.jpg', 'Springer London, Limited', NULL, NULL),
(6036, 'L. Franklyn Elliott M.D.James H. French Jr.James C. GrottingMcKay McKinnonMichael H. MosesRichard S. StahlBryant A. TothVincent N. Zubowicz', '', '978-1-4612-1896-8', 5430, 0, '1997', 'Flaps: Decision Making in Clinical Practice is an excellent readable guide for surgeons utilizing multiple techniques in plastic and reconstructive surgery. The authors have organized a pragmatic guide, specifically focused on those flaps which surgeons find difficult and challenging, with the latest technical developments in all anatomical areas.', 'FLAPS', 'http://link.springer.com/book/10.1007/978-1-4612-1896-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4612-1896-8.jpg', 'Springer London, Limited', NULL, NULL),
(6037, 'Dr. J. J. PindborgDr. P. A. ReichartDr. C. J. SmithDr. I. van der Waal', '', '978-3-642-60592-5', 5430, 0, '1997', 'There are two major differences in concept between this volume and others in the International Histological Classification of Tu­ mours series. The first of these is the inclusion of more clinical aspects than has usually been the case and the second is a con­ centration on a more limited range of conditions. There are sev­ eral reasons for adopting this approach. With regard to both cancer and pre cancer of the oral mucosa, we believe it is impor­ tant that general pathologists, in whose interests this volume has primarily been written, should be informed of the significance of the clinical features of the various lesions under discussion as they may on the whole be unfamiliar with them. Also, we con­ sider it necessary to draw attention to those conditions particu­ lar to the oral tissues that may give rise to appearances which are important in differential diagnosis but can be misleading to the pathologist who does not have detailed knowledge of these tissues. On the other hand, many of the benign and malignant tumours that affect the oral tissues have been dealt with in other volumes in the series and we believe that little or no advantage would be gained by repeating them here.', 'Histological Typing of Cancer and Precancer of the Oral Mucosa', 'http://link.springer.com/book/10.1007/978-3-642-60592-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-60592-5.jpg', 'Springer London, Limited', NULL, NULL),
(6038, 'Prof. Dr. IsaÃ¤c van der Waal', '', '978-3-642-80274-4', 5430, 0, '1997', 'Both the major and minor salivary glands can be the site of a wide variety of diseases and functional disturbances. This monograph covers both the common lesions and conditions of the salivary glands as well as the rare ones. Much attention is given to the problematic complaint of dry mouth and the even more cumbersome diagnostic aspects of Sjögren\'s syndrome. Emphasis is on the clinical aspects and the management of the various disorders. The vast experience of the authors is reflected in their clear and concise style. The illustrations are well chosen and updated references are provided, where appropriate.', 'Diseases of the Salivary Glands Including Dry Mouth and SjÃ¶grenâ€™s Syndrome', 'http://link.springer.com/book/10.1007/978-3-642-80274-4', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-80274-4.jpg', 'Springer London, Limited', NULL, NULL),
(6039, 'Oscar M. Ramirez M.D., FACSRollin K. Daniel M.D., FACS', '', '978-1-4612-2328-3', 11940, 0, '1996', 'Endoscopic Techniques in Plastic and Aesthetic Surgery comprehensively addresses both the aesthetic and reconstructive aspects of endoscopic surgery as applied to plastic surgery. The editors, renowned pioneers of these techniques, have assembled a group of distinguished contributors to present, step-by-step, the operative strategies for incorporation of endoscopic procedures to the armamentarium of the practicing plastic surgeon. The procedures are precisely and exquisitely rendered by 721 illustrations, including over 300 full color endoscopic views and operative photographs. This book is the essential, definitive source for mastery of these state-of-the-art techniques.', 'Endoscopic Plastic Surgery', 'http://link.springer.com/book/10.1007/978-1-4612-2328-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4612-2328-3.jpg', 'Springer London, Limited', NULL, NULL),
(6040, 'Prof. Dr. med. dent. H.-D. PapeProf. Dr. med. U. GanzerProf. Dr. med. G. Schmitt', '', '978-3-642-84971-8', 9770, 0, '1994', 'In spite of great advance made by ENT and maxillofacial surgeons as well as radiotherapists to improve therapy of cancer of the oral cavity and oropharynx, it has not been possible in the past 4 decades to raise the chances of patient survival above 40%-45%. However, recent studies with different combination therapies indicate that better results can be expected in the future. In this volume, the current status and results of therapeutic studies are presented by distinguished clinicians in the three disciplines. The book provides up-to-date information and encourages interdisciplinary cooperation.', 'Carcinoma of the Oral Cavity and Oropharynx', 'http://link.springer.com/book/10.1007/978-3-642-84971-8', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-84971-8.jpg', NULL, NULL, NULL);
INSERT INTO `book` (`id`, `author`, `edition`, `isbn`, `price`, `quantity`, `year`, `description`, `book_title`, `url`, `cover_image`, `publisher`, `status`, `created_at`) VALUES
(6041, 'Alex M. Greenberg D.D.S.', '', '978-1-4613-9287-3', 8360, 0, '1993', 'The atlas format of Craniomaxiollofacial Fracturesclearly shows how to manage fractures to the head, face and jaw bones with rigid internal fixation. All fractures, from the simple to the most complex, are covered. The book is ideal for physicians from various specialties who diagnose, treat or refer craniomaxillofacial trauma. It describes for the first time the classical fracture types most commonly encountered and their representations by standard radiographs and diagrams. The AO system is prominently featured throughout the atlas.', 'Craniomaxillofacial Fractures', 'http://link.springer.com/book/10.1007/978-1-4613-9287-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4613-9287-3.jpg', 'Springer', NULL, NULL),
(6042, 'I. R. H. KramerJ. J. PindborgM. Shear', '', '978-3-662-02858-2', 15190, 0, '1992', 'Inter-relationships of the Dental Tissues The tooth germ has three main components -the enamel organ, the dental papilla and the dental follicle (Fig. 1). The enamel organ is an epithelial structure derived from the ectoderm that lines much of the oral cavity. The dental papilla and the dental follicle are ectomesen­ chymal (mesectodermal), being partly derived from cells that mi­ grated from the neural crest early in embryogenesis. Both the gross morphology of the tooth germ and the differentiation of its cells de­ pend upon a complex pattern of inductive interactions between the epithelium and the ectomesenchyme. The sites in which the teeth will form appear to be determined before the commencement of epithelial downgrowth from the oral epithelium to form the odontogenic epithelium. This epithelial downgrowth (the dental lamina ), the development of the enamel or­ gans of the individual teeth, and the morphology of each enamel organ, are controlled by the ectomesenchyme. The enamel organ is responsible for the formation of enamel and comprises four layers: outer dental epithelium, stellate reticulum, stratum intermedium and inner dental epithelium (Figs. 1 and 2a).', 'Histological Typing of Odontogenic Tumours', 'http://link.springer.com/book/10.1007/978-3-662-02858-2', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-662-02858-2.jpg', 'Springer London, Limited', NULL, NULL),
(6043, 'Louis M. Abbey D.M.D., M.S.John L. Zimmerman D.D.S.', '', '978-1-4613-9160-9', 9770, 0, '1992', 'Dentistry today is changing because of new knowledge networks based on electronic technology. This book tells practitioners, administrators and educators what is happening in dentistry and how to use the full potential of new information technologies. Specifics such as existing machines, operating systems, software packages and user support groups are discussed. Aspects of standards for storage, access, and the use of information as well as its integration into the dental practice are covered. More general topics cover the impact of dental informatics on dentistry training programs, the dental manufacturing industries and insurance.', 'Dental Informatics', 'http://link.springer.com/book/10.1007/978-1-4613-9160-9', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4613-9160-9.jpg', 'Springer', NULL, NULL),
(6044, 'Professor Dr. med. Prof. h.c. Madjid SamiiProfessor Dr. med. Engelbert Knosp', '', '978-3-642-76614-5', 5430, 0, '1992', NULL, 'Approaches to the Clivus', 'http://link.springer.com/book/10.1007/978-3-642-76614-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-76614-5.jpg', 'Springer London, Limited', NULL, NULL),
(6045, 'M. Leon Skolnick M.D.Ellen R. Cohn Ph.D.', '', '978-1-4613-8874-6', 5430, 0, '1989', 'In Videofluorscopic Studies of Speech in Patients with Cleft Palate, Drs. M.L. Skolnick and E.R. Cohn present multiview videofluoroscopy as a technique for the radiological evaluation of speech defects in patients with cleft palate. Dr. Skolnick\'s invaluable contributions as both the originator and leading authority on the subject are discussed in a concise, clinical fashion. Topics examined include the anatomy and imaging of the velopharyngeal portal; the equipment and techniques of multiview videofluoroscopy; the interpretation of results and various patterns of velopharyngeal closure; Passavant\'s Ridge and patterns of velopharyngeal closure; normal and abnormal speech production; and the evaluation of test results. This book is the only source which concisely and completely describes the technique and its interpretations for those who need a description of the clinical procedure.', 'Videofluoroscopic Studies of Speech in Patients with Cleft Palate', 'http://link.springer.com/book/10.1007/978-1-4613-8874-6', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4613-8874-6.jpg', 'Springer New York', NULL, NULL),
(6046, 'Dr. B. K. B. BerkovitzProf. Dr. A. BoydeProf. Dr. R. M. FrankProf. Dr. H. J. HÃ¶hlingDr. B. J. MoxhamDr. J. NalbandianC. H. Tonge', '', '978-3-642-83496-7', 5430, 0, '1989', 'The editors and the publisher are pleased to present another volume in this series of monographs. The topic of teeth was last reviewed within the framework of this Handbook more than fifty years ago, in 1936, by Josef Lehner and HanDs Plenk of Vienna, who wrote a comprehensive treatise on the subject in volume V 3. / The introduction of new methods (e.g., transmission and scan­ ning electron microscopy, histochemistry, radioautography, element analysis) and progress in dental research have made an update necessary. In present times, characterized by scientific specialization and very rapid progress, it is virtually impossible to find a single individual prepared to review a field of research as large as that of teeth. Consequently. several authors were asked to contribute to the present volume. Originally. the intention was to cover the field in one volume. When it became clear that the material had become too extensive for a single volume, and when some authors were forced by external factors to withdraw from the project, it was decided to publish two volumes. In 1986, the volume Periodontium, written by Hubert E. Schroeder of Zurich. appeared in this series (volume VIS, 418 pages).', 'Teeth', 'http://link.springer.com/book/10.1007/978-3-642-83496-7', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-83496-7.jpg', 'Springer London, Limited', NULL, NULL),
(6047, 'John Dobbing DSc, FRCP, FRCPath', '', '978-1-4471-1652-3', 13020, 0, '1988', 'A Balanced Diet? is an attempt to answer the next question which consumers always ask when advised by their doctors or other health professionals, or the media, to eat one. What is it? Of course a balanced diet is a concept, and may be simply expressed as a diet which, over a period of time, provides all the dietary constituents which are required for healthy living, and which helps avoid disease states so far as these may be attributable to unhealthy eating. A group of leading nutritionists and doctors has attempted to describe in this book the guidelines for which such a diet may be devised. The authors have tried to face the many controversies and to resolve them, always with reference to evidence before mere belief. It is hoped that the reader will be better equipped after reading this book, whether he be doctor, paramedic, or plain, ordinary citizen, to confront the enormous body of material with which he is surrounded every day.', 'A Balanced Diet?', 'http://link.springer.com/book/10.1007/978-1-4471-1652-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-1-4471-1652-3.jpg', NULL, NULL, NULL),
(6048, 'Prithvi RajHans NolteMichael Stanton-Hicks', '', '978-3-642-61389-0', 5430, 0, '1988', NULL, 'Illustrated Manual of Regional Anesthesia', 'http://link.springer.com/book/10.1007/978-3-642-61389-0', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-61389-0.jpg', 'Springer London, Limited', NULL, NULL),
(6049, 'Professor Dr. GÃ¼nther SchlagDoz. Dipl.-Ing. Dr. Heinz Redl', '', '978-3-642-82880-5', 15190, 0, '1986', 'Fibrin plays a prominent role in wound healing. It has a hemostatic effect, induces cellular response to wound damage, and, by forming strands to build a matrix, assists in neovascularization and fibroblast proliferation. The concept of using clotting substances from human blood for wound manage­ ment and to achieve hemostasis in bleeding parenchymatous organs can be traced to 1909, when Bergel [1] reported on the hemostatic effect offibrin powder. In 1915, Grey [3] employed fibrin to control bleeding in neurosurgical operations of the brain. A year later, Harvey [4] used fibrin patches to stop bleeding from parenchy­ matous organs in general surgery. It took more than two decades for this ingenious idea to be rediscovered. In 1940, Young and Medawar [8] reported on experimental nerve anastomosis by sealing. Similarly, Tarlov and Benjamin [7] reunited nerves with plasma clots in 1943. Tarlov improved the results obtained with clot anastomosing of nerves by avoiding tension at the nerve stumps. In 1944, Cronkite et al. [2] reported on an initial series of eight cases in which fibrinogen and thrombin had been used successfully for anchoring skin grafts.', 'Fibrin Sealant in Operative Medicine', 'http://link.springer.com/book/10.1007/978-3-642-82880-5', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-82880-5.jpg', NULL, NULL, NULL),
(6050, 'Rigmor TexhammarRoland R. Schmoker M.D., D.M.D.', '', '978-3-642-69858-3', 5430, 0, '1984', 'Functionally stable internal fixation is of particular relevance to maxillo­ facial surgery, because it obviates the discomforts and inconveniences of intermaxillary fixation. Given the biomechanics and biophysics of the skeletal system, the true im­ mobilization of bone can be achieved only through highly technical means. Willenegger speaks of an \"advanced school\" of bone surgery which, when fully realized, will enable excellent results to be achieved even in the most difficult fractures. To accomplish this goal, ongoing refinements are needed in surgical methods and technology. Advancing the state of operative tech­ nique has been a central concern of the Association for the Study of Inter­ nal Fixation since its establishment 25 years ago. For this reason, a major priority of the AOI ASIF has been to develop its own surgical instrumen­ tation. With the help of technical commissions comprised of experts from medi­ cine, research and manufacturing, the AOI ASIF has been able to develop and successfully test a line of surgical instruments whose trademark is known and respected the world over. For every specialty in traumatology and orthopaedics, including maxillofacial surgery, the AOIASIF has devel­ oped both a basic and a special instrument set designed to meet specific anatomic requirements.', 'Stable Internal Fixation in Maxillofacial Bone Surgery', 'http://link.springer.com/book/10.1007/978-3-642-69858-3', 'https://media.springernature.com/w153/springer-static/cover/book/978-3-642-69858-3.jpg', 'Springer', NULL, NULL),
